222‚Üí// inferSenderDomain tries to detect the sender's domain from connected email.
223‚Üífunc inferSenderDomain(d *sql.DB) string {
224‚Üí	var fromEmail string
225‚Üí	err := d.QueryRow("SELECT from_email FROM emails LIMIT 1").Scan(&fromEmail)
226‚Üí	if err != nil {
227‚Üí		return ""
228‚Üí	}
229‚Üí	parts := strings.SplitN(fromEmail, "@", 2)
230‚Üí	if len(parts) == 2 {
231‚Üí		return strings.ToLower(parts[1])
232‚Üí	}
233‚Üí	return ""
234‚Üí}
