  1‚Üípackage project
  2‚Üí
  3‚Üíimport (
  4‚Üí	"encoding/json"
  5‚Üí	"fmt"
  6‚Üí	"os"
  7‚Üí	"path/filepath"
  8‚Üí	"time"
  9‚Üí)
 10‚Üí
 11‚Üíconst configFile = ".nurge/config.json"
 12‚Üíconst configLockFile = ".nurge/config.lock"
 13‚Üí
 14‚Üí// withConfigLock acquires an exclusive file lock on the config lockfile,
 15‚Üí// runs fn, then releases the lock. This prevents TOCTOU race conditions
 16‚Üí// when multiple processes do Load -> modify -> Write concurrently.
 17‚Üífunc withConfigLock(fn func() error) error {
 18‚Üí	f, err := os.OpenFile(configLockFile, os.O_CREATE|os.O_RDWR, 0600)
 19‚Üí	if err != nil {
 20‚Üí		return fmt.Errorf("opening config lock: %w", err)
 21‚Üí	}
 22‚Üí	defer f.Close()
 23‚Üí
 24‚Üí	if err := flockExclusive(int(f.Fd())); err != nil {
 25‚Üí		return fmt.Errorf("acquiring config lock: %w", err)
 26‚Üí	}
 27‚Üí	defer flockUnlock(int(f.Fd()))
 28‚Üí
 29‚Üí	return fn()
 30‚Üí}
 31‚Üí
 32‚Üí// ConnectorState holds the state of a single connected service.
 33‚Üítype ConnectorState struct {
 34‚Üí	Connected   bool   `json:"connected"`
 35‚Üí	ConnectedAt string `json:"connected_at,omitempty"`
 36‚Üí	Account     string `json:"account,omitempty"`
 37‚Üí	Type        string `json:"type"` // "crm" or "email"
 38‚Üí}
 39‚Üí
 40‚Üí// Config is the top-level nurge configuration.
 41‚Üítype Config struct {
 42‚Üí	Version        int                        `json:"version"`
 43‚Üí	CreatedAt      string                     `json:"created_at"`
 44‚Üí	Connectors     map[string]ConnectorState  `json:"connectors"`
 45‚Üí	SetupCompleted bool                       `json:"setup_completed"`
 46‚Üí	Settings       map[string]string          `json:"settings,omitempty"`
 47‚Üí}
 48‚Üí
 49‚Üí// Path returns the path to config.json.
 50‚Üífunc Path() string {
 51‚Üí	return configFile
 52‚Üí}
 53‚Üí
 54‚Üí// Default returns a new Config with default values.
 55‚Üífunc Default() *Config {
 56‚Üí	return &Config{
 57‚Üí		Version:        1,
 58‚Üí		CreatedAt:      time.Now().UTC().Format(time.RFC3339),
 59‚Üí		Connectors:     make(map[string]ConnectorState),
 60‚Üí		SetupCompleted: false,
 61‚Üí	}
 62‚Üí}
 63‚Üí
 64‚Üí// Load reads config from disk.
 65‚Üífunc Load() (*Config, error) {
 66‚Üí	data, err := os.ReadFile(configFile)
 67‚Üí	if err != nil {
 68‚Üí		return nil, fmt.Errorf("reading config: %w", err)
 69‚Üí	}
 70‚Üí	var cfg Config
 71‚Üí	if err := json.Unmarshal(data, &cfg); err != nil {
 72‚Üí		return nil, fmt.Errorf("parsing config: %w", err)
 73‚Üí	}
 74‚Üí	if cfg.Connectors == nil {
 75‚Üí		cfg.Connectors = make(map[string]ConnectorState)
 76‚Üí	}
 77‚Üí	return &cfg, nil
 78‚Üí}
 79‚Üí
 80‚Üí// Write saves config to disk.
 81‚Üífunc Write(cfg *Config) error {
 82‚Üí	data, err := json.MarshalIndent(cfg, "", "  ")
 83‚Üí	if err != nil {
 84‚Üí		return fmt.Errorf("marshaling config: %w", err)
 85‚Üí	}
 86‚Üí	if err := os.WriteFile(configFile, data, 0600); err != nil {
 87‚Üí		return fmt.Errorf("writing config: %w", err)
 88‚Üí	}
 89‚Üí	return nil
 90‚Üí}
 91‚Üí
 92‚Üí// SetConnector updates a connector in the config and saves.
 93‚Üífunc SetConnector(id, connType, account string) error {
 94‚Üí	return withConfigLock(func() error {
 95‚Üí		cfg, err := Load()
 96‚Üí		if err != nil {
 97‚Üí			return err
 98‚Üí		}
 99‚Üí		cfg.Connectors[id] = ConnectorState{
100‚Üí			Connected:   true,
101‚Üí			ConnectedAt: time.Now().UTC().Format(time.RFC3339),
102‚Üí			Account:     account,
103‚Üí			Type:        connType,
104‚Üí		}
105‚Üí		return Write(cfg)
106‚Üí	})
107‚Üí}
108‚Üí
109‚Üí// RemoveConnector removes a connector from config and saves.
110‚Üífunc RemoveConnector(id string) error {
111‚Üí	return withConfigLock(func() error {
112‚Üí		cfg, err := Load()
113‚Üí		if err != nil {
114‚Üí			return err
115‚Üí		}
116‚Üí		delete(cfg.Connectors, id)
117‚Üí		return Write(cfg)
118‚Üí	})
119‚Üí}
120‚Üí
121‚Üí// Get returns the value for a settings key, or empty string if not set.
122‚Üífunc Get(key string) (string, error) {
123‚Üí	cfg, err := Load()
124‚Üí	if err != nil {
125‚Üí		return "", err
126‚Üí	}
127‚Üí	if cfg.Settings == nil {
128‚Üí		return "", nil
129‚Üí	}
130‚Üí	return cfg.Settings[key], nil
131‚Üí}
132‚Üí
133‚Üí// Set stores a key/value pair in settings and saves the config.
134‚Üífunc Set(key, value string) error {
135‚Üí	return withConfigLock(func() error {
136‚Üí		cfg, err := Load()
137‚Üí		if err != nil {
138‚Üí			return err
139‚Üí		}
140‚Üí		if cfg.Settings == nil {
141‚Üí			cfg.Settings = make(map[string]string)
142‚Üí		}
143‚Üí		cfg.Settings[key] = value
144‚Üí		return Write(cfg)
145‚Üí	})
146‚Üí}
147‚Üí
148‚Üí// SetSetupCompleted sets the top-level setup_completed flag and saves.
149‚Üí// When marking as complete, also removes the global setup skill -- it's no longer needed.
150‚Üífunc SetSetupCompleted(completed bool) error {
151‚Üí	return withConfigLock(func() error {
152‚Üí		cfg, err := Load()
153‚Üí		if err != nil {
154‚Üí			return err
155‚Üí		}
156‚Üí		cfg.SetupCompleted = completed
157‚Üí		if err := Write(cfg); err != nil {
158‚Üí			return err
159‚Üí		}
160‚Üí		if completed {
161‚Üí			removeSetupSkill()
162‚Üí		}
163‚Üí		return nil
164‚Üí	})
165‚Üí}
166‚Üí
167‚Üí// removeSetupSkill deletes the global setup skill directory.
168‚Üí// Graceful ‚Äî ignores errors if already removed.
169‚Üífunc removeSetupSkill() {
170‚Üí	home, err := os.UserHomeDir()
171‚Üí	if err != nil {
172‚Üí		return
173‚Üí	}
174‚Üí	os.RemoveAll(filepath.Join(home, ".claude", "skills", "nurge-setup"))
175‚Üí}
