 25‚Üí
 26‚Üívar sendCmd = &cobra.Command{
 27‚Üí	Use:   "send",
 28‚Üí	Short: "Send an email via Unipile",
 29‚Üí	Long:  "Send an email through your connected email account via Convex + Unipile.",
 30‚Üí	RunE: func(cmd *cobra.Command, args []string) error {
 31‚Üí		if sendSequence != "" && sendTaskID != "" {
 32‚Üí			return fmt.Errorf("--sequence and --task-id cannot be used together")
 33‚Üí		}
 34‚Üí
 35‚Üí		// Load auth token
 36‚Üí		authFile, err := account.LoadAuth()
 37‚Üí		if err != nil || authFile.Token == "" {
 38‚Üí			return fmt.Errorf("not logged in. Run: nurge account login")
 39‚Üí		}
 40‚Üí
 41‚Üí		// If --task-id is provided, resolve draft content from local DB for defaults
 42‚Üí		if sendTaskID != "" {
 43‚Üí			d, err := db.Open()
 44‚Üí			if err != nil {
 45‚Üí				return fmt.Errorf("opening database: %w", err)
 46‚Üí			}
 47‚Üí			defer d.Close()
 48‚Üí
 49‚Üí			task, err := sequence.TaskByID(d, sendTaskID)
 50‚Üí			if err != nil {
 51‚Üí				return err
 52‚Üí			}
 53‚Üí			if sendTo == "" {
 54‚Üí				sendTo = task.ContactEmail
 55‚Üí			} else if !strings.EqualFold(strings.TrimSpace(sendTo), strings.TrimSpace(task.ContactEmail)) {
 56‚Üí				return fmt.Errorf("--task-id %s belongs to %s, but --to was %s", task.ID, task.ContactEmail, sendTo)
 57‚Üí			}
 58‚Üí			if sendSubject == "" || sendBody == "" {
 59‚Üí				renderedSubject, renderedBody, err := sequence.RenderTaskContent(d, *task)
 60‚Üí				if err != nil {
 61‚Üí					return err
 62‚Üí				}
 63‚Üí				if sendSubject == "" {
 64‚Üí					sendSubject = renderedSubject
 65‚Üí				}
 66‚Üí				if sendBody == "" {
 67‚Üí					sendBody = renderedBody
 68‚Üí				}
 69‚Üí			}
 70‚Üí		}
 71‚Üí
 72‚Üí		if sendTo == "" {
 73‚Üí			return fmt.Errorf("recipient (--to) is required")
 74‚Üí		}
 75‚Üí		if sendSubject == "" {
 76‚Üí			return fmt.Errorf("subject (--subject) is required")
 77‚Üí		}
 78‚Üí		if sendBody == "" {
 79‚Üí			return fmt.Errorf("body (--body) is required")
 80‚Üí		}
 81‚Üí
 82‚Üí		// Build request
 83‚Üí		req := account.SendEmailRequest{
 84‚Üí			To:       strings.TrimSpace(sendTo),
 85‚Üí			Cc:       strings.TrimSpace(sendCc),
 86‚Üí			Subject:  sendSubject,
 87‚Üí			Body:     sendBody,
 88‚Üí			SendType: sequence.NormalizeSendType(sendSendType),
 89‚Üí			Sync:     true, // CLI-initiated sends are always sync
 90‚Üí			TaskID:   sendTaskID,
 91‚Üí		}
 92‚Üí
 93‚Üí		// Sequence enrollment
 94‚Üí		if sendSequence != "" {
 95‚Üí			req.SendType = sequence.SendTypeFirstTouch
 96‚Üí
 97‚Üí			d, err := db.Open()
 98‚Üí			if err != nil {
 99‚Üí				return fmt.Errorf("opening database: %w", err)
100‚Üí			}
101‚Üí			defer d.Close()
102‚Üí
103‚Üí			seqReq := &account.SequenceRequest{
104‚Üí				SequenceName: sendSequence,
105‚Üí				CampaignName: sendCampaign,
106‚Üí				ContactName:  sendContactName,
107‚Üí			}
108‚Üí
109‚Üí			// Best-effort mailbox resolution for Convex
110‚Üí			if sendCampaign != "" {
111‚Üí				if campaign, cErr := sequence.CampaignByName(d, sendCampaign); cErr == nil {
112‚Üí					if mbx, mErr := sequence.CampaignMailbox(d, campaign); mErr == nil && mbx != nil {
113‚Üí						seqReq.MailboxID = mbx.ID
114‚Üí					}
115‚Üí				}
116‚Üí			}
117‚Üí
118‚Üí			// Get steps from built-in template
119‚Üí			tmpl, tmplErr := sequence.TemplateByName(d, sendSequence)
120‚Üí			if tmplErr == nil {
121‚Üí				for _, step := range tmpl.Steps {
122‚Üí					if step.StepNumber <= 1 {
123‚Üí						continue // skip first touch, that's the current send
124‚Üí					}
125‚Üí					seqReq.Steps = append(seqReq.Steps, account.SequenceStep{
126‚Üí						StepNumber: step.StepNumber,
127‚Üí						StepName:   step.Name,
128‚Üí						SendType:   step.SendType,
129‚Üí						DelayDays:  parseDays(step.Delay),
130‚Üí					})
131‚Üí				}
132‚Üí			}
133‚Üí
134‚Üí			req.Sequence = seqReq
135‚Üí		}
136‚Üí
137‚Üí		// Call Convex
138‚Üí		client := account.NewConvexClient(cmdutil.GetConvexURL())
139‚Üí		resp, err := client.SendEmail(authFile.Token, req)
140‚Üí		if err != nil {
141‚Üí			return fmt.Errorf("send failed: %w", err)
142‚Üí		}
143‚Üí
144‚Üí		if resp.Queued {
145‚Üí			fmt.Printf("  \033[33m‚è≥\033[0m Queued for %s (task: %s)\n", sendTo, resp.TaskID)
146‚Üí		} else {
147‚Üí			fmt.Printf("  \033[32m‚úì\033[0m Sent to %s (message ID: %s)\n", sendTo, resp.MessageID)
148‚Üí		}
149‚Üí
150‚Üí		if resp.EnrollmentID != "" {
151‚Üí			fmt.Printf("  ‚Ü≥ Enrolled in sequence %s (%s)\n", sendSequence, resp.EnrollmentID)
152‚Üí		}
153‚Üí
154‚Üí		return nil
155‚Üí	},
156‚Üí}
