160‚Üí	sendCmd.Flags().StringVar(&sendCc, "cc", "", "CC email address")
161‚Üí	sendCmd.Flags().StringVar(&sendSubject, "subject", "", "Email subject")
162‚Üí	sendCmd.Flags().StringVar(&sendBody, "body", "", "Email body (plain text)")
163‚Üí	sendCmd.Flags().StringVar(&sendSequence, "sequence", "", "Enroll the sent email in a built-in sequence template")
164‚Üí	sendCmd.Flags().StringVar(&sendCampaign, "campaign", "", "Optional campaign name stored on the sequence enrollment")
165‚Üí	sendCmd.Flags().StringVar(&sendTaskID, "task-id", "", "Mark a follow-up task as sent and advance the sequence")
166‚Üí	sendCmd.Flags().StringVar(&sendSendType, "send-type", "", "Override send classification (first_touch, follow_up, reply, manual)")
