170‚Üí// parseDays extracts day count from a duration string like "3d" or "72h".
171‚Üífunc parseDays(delay string) int {
172‚Üí	delay = strings.TrimSpace(delay)
173‚Üí	if delay == "" || delay == "0s" {
174‚Üí		return 0
175‚Üí	}
176‚Üí	// Handle "Xd" format
177‚Üí	if strings.HasSuffix(delay, "d") {
178‚Üí		var d int
179‚Üí		fmt.Sscanf(delay, "%dd", &d)
180‚Üí		return d
181‚Üí	}
182‚Üí	// Handle "Xh" format
183‚Üí	if strings.HasSuffix(delay, "h") {
184‚Üí		var h int
185‚Üí		fmt.Sscanf(delay, "%dh", &h)
186‚Üí		return h / 24
187‚Üí	}
188‚Üí	return 3 // default
189‚Üí}
