 5‚Üítype ClassifyUpdate struct {
 6‚Üí	ID           string  `json:"id"`
 7‚Üí	Class        string  `json:"class"`
 8‚Üí	Confidence   float64 `json:"confidence"`
 9‚Üí	ClassifiedBy string  `json:"classified_by"`
10‚Üí}
11‚Üí
12‚Üífunc Classify(d *sql.DB, updates []ClassifyUpdate) (int, error) {
13‚Üí	tx, err := d.Begin()
14‚Üí	if err != nil {
15‚Üí		return 0, err
16‚Üí	}
17‚Üí	defer tx.Rollback()
18‚Üí
19‚Üí	stmt, err := tx.Prepare("UPDATE emails SET class = ?, class_confidence = ?, classified_by = ? WHERE id = ?")
20‚Üí	if err != nil {
21‚Üí		return 0, err
22‚Üí	}
23‚Üí	defer stmt.Close()
24‚Üí
25‚Üí	count := 0
26‚Üí	for _, u := range updates {
27‚Üí		if u.ClassifiedBy == "" {
28‚Üí			u.ClassifiedBy = "claude"
29‚Üí		}
30‚Üí		res, err := stmt.Exec(u.Class, u.Confidence, u.ClassifiedBy, u.ID)
31‚Üí		if err != nil {
32‚Üí			return count, err
33‚Üí		}
34‚Üí		n, _ := res.RowsAffected()
35‚Üí		count += int(n)
36‚Üí	}
37‚Üí
38‚Üí	return count, tx.Commit()
39‚Üí}
