  1‚Üípackage email
  2‚Üí
  3‚Üíimport (
  4‚Üí	"database/sql"
  5‚Üí	"encoding/json"
  6‚Üí	"strings"
  7‚Üí)
  8‚Üí
  9‚Üí// AutoClassifyResult reports what the heuristic classifier did.
 10‚Üítype AutoClassifyResult struct {
 11‚Üí	Total        int            `json:"total"`
 12‚Üí	Classified   int            `json:"classified"`
 13‚Üí	Remaining    int            `json:"remaining"`
 14‚Üí	ByClass      map[string]int `json:"by_class"`
 15‚Üí	SenderDomain string         `json:"-"` // caller's domain, used internally
 16‚Üí}
 17‚Üí
 18‚Üí// ClassifyAuto applies deterministic heuristics to unclassified emails.
 19‚Üí// senderDomain is the user's sending domain (e.g. "acme.com").
 20‚Üí// Returns a summary of what was classified and how many remain for Claude.
 21‚Üífunc ClassifyAuto(d *sql.DB, senderDomain string) (*AutoClassifyResult, error) {
 22‚Üí	senderDomain = strings.ToLower(strings.TrimSpace(senderDomain))
 23‚Üí
 24‚Üí	// Fetch all unclassified emails.
 25‚Üí	rows, err := d.Query(`SELECT id, from_email, to_emails, subject, snippet FROM emails WHERE class = 'unclassified'`)
 26‚Üí	if err != nil {
 27‚Üí		return nil, err
 28‚Üí	}
 29‚Üí	defer rows.Close()
 30‚Üí
 31‚Üí	type candidate struct {
 32‚Üí		id      string
 33‚Üí		from    string
 34‚Üí		to      string // JSON array
 35‚Üí		subject string
 36‚Üí		snippet string
 37‚Üí	}
 38‚Üí
 39‚Üí	var candidates []candidate
 40‚Üí	for rows.Next() {
 41‚Üí		var c candidate
 42‚Üí		var subj, snip sql.NullString
 43‚Üí		if err := rows.Scan(&c.id, &c.from, &c.to, &subj, &snip); err != nil {
 44‚Üí			return nil, err
 45‚Üí		}
 46‚Üí		c.subject = subj.String
 47‚Üí		c.snippet = snip.String
 48‚Üí		candidates = append(candidates, c)
 49‚Üí	}
 50‚Üí	if err := rows.Err(); err != nil {
 51‚Üí		return nil, err
 52‚Üí	}
 53‚Üí
 54‚Üí	// Classify with heuristics.
 55‚Üí	var updates []ClassifyUpdate
 56‚Üí	result := &AutoClassifyResult{
 57‚Üí		Total:   len(candidates),
 58‚Üí		ByClass: make(map[string]int),
 59‚Üí	}
 60‚Üí
 61‚Üí	for _, c := range candidates {
 62‚Üí		class := classifyHeuristic(c.from, c.to, c.subject, c.snippet, senderDomain)
 63‚Üí		if class == "" {
 64‚Üí			continue // ambiguous ‚Äî leave for Claude
 65‚Üí		}
 66‚Üí		updates = append(updates, ClassifyUpdate{
 67‚Üí			ID:           c.id,
 68‚Üí			Class:        class,
 69‚Üí			Confidence:   0.85,
 70‚Üí			ClassifiedBy: "auto",
 71‚Üí		})
 72‚Üí		result.ByClass[class]++
 73‚Üí	}
 74‚Üí
 75‚Üí	// Batch update in one transaction.
 76‚Üí	if len(updates) > 0 {
 77‚Üí		if _, err := Classify(d, updates); err != nil {
 78‚Üí			return nil, err
 79‚Üí		}
 80‚Üí	}
 81‚Üí
 82‚Üí	result.Classified = len(updates)
 83‚Üí	result.Remaining = result.Total - result.Classified
 84‚Üí	return result, nil
 85‚Üí}
 86‚Üí
 87‚Üífunc classifyHeuristic(from, toJSON, subject, snippet, senderDomain string) string {
 88‚Üí	fromLower := strings.ToLower(from)
 89‚Üí	subjLower := strings.ToLower(subject)
 90‚Üí	snipLower := strings.ToLower(snippet)
 91‚Üí
 92‚Üí	// Parse recipient list.
 93‚Üí	var recipients []string
 94‚Üí	_ = json.Unmarshal([]byte(toJSON), &recipients)
 95‚Üí
 96‚Üí	// --- Transactional signals ---
 97‚Üí	transactionalPrefixes := []string{
 98‚Üí		"noreply@", "no-reply@", "donotreply@", "do-not-reply@",
 99‚Üí		"mailer-daemon@", "postmaster@", "notifications@", "notify@",
100‚Üí		"support@", "billing@", "receipts@", "invoice@",
101‚Üí	}
102‚Üí	for _, prefix := range transactionalPrefixes {
103‚Üí		if strings.HasPrefix(fromLower, prefix) {
104‚Üí			return "transactional"
105‚Üí		}
106‚Üí	}
107‚Üí	// Transactional subjects.
108‚Üí	transactionalSubjects := []string{
109‚Üí		"password reset", "verify your email", "confirm your",
110‚Üí		"your receipt", "your invoice", "your order", "payment confirmation",
111‚Üí		"subscription", "account activation", "welcome to",
112‚Üí	}
113‚Üí	for _, sig := range transactionalSubjects {
114‚Üí		if strings.Contains(subjLower, sig) {
115‚Üí			return "transactional"
116‚Üí		}
117‚Üí	}
118‚Üí
119‚Üí	// --- Internal signals ---
120‚Üí	// All recipients share the same domain as sender.
121‚Üí	if senderDomain != "" && len(recipients) > 0 {
122‚Üí		allInternal := true
123‚Üí		for _, r := range recipients {
124‚Üí			if !strings.HasSuffix(strings.ToLower(r), "@"+senderDomain) {
125‚Üí				allInternal = false
126‚Üí				break
127‚Üí			}
128‚Üí		}
129‚Üí		if allInternal {
130‚Üí			return "internal"
131‚Üí		}
132‚Üí	}
133‚Üí
134‚Üí	// --- Newsletter signals ---
135‚Üí	newsletterSubjects := []string{
136‚Üí		"newsletter", "digest", "weekly update", "monthly update",
137‚Üí		"unsubscribe", "weekly roundup",
138‚Üí	}
139‚Üí	for _, sig := range newsletterSubjects {
140‚Üí		if strings.Contains(subjLower, sig) || strings.Contains(snipLower, sig) {
141‚Üí			return "newsletter"
142‚Üí		}
143‚Üí	}
144‚Üí
145‚Üí	// --- Personal signals ---
146‚Üí	// Single recipient, personal domain, short/casual subject.
147‚Üí	personalDomains := map[string]bool{
148‚Üí		"gmail.com": true, "yahoo.com": true, "hotmail.com": true,
149‚Üí		"outlook.com": true, "icloud.com": true, "aol.com": true,
150‚Üí		"protonmail.com": true, "me.com": true, "live.com": true,
151‚Üí	}
152‚Üí	if len(recipients) == 1 {
153‚Üí		parts := strings.SplitN(recipients[0], "@", 2)
154‚Üí		if len(parts) == 2 && personalDomains[strings.ToLower(parts[1])] {
155‚Üí			// Sender is also from a personal domain ‚Üí personal.
156‚Üí			fromParts := strings.SplitN(from, "@", 2)
157‚Üí			if len(fromParts) == 2 && personalDomains[strings.ToLower(fromParts[1])] {
158‚Üí				return "personal"
159‚Üí			}
160‚Üí		}
161‚Üí	}
162‚Üí
163‚Üí	// No confident match ‚Äî leave for Claude.
164‚Üí	return ""
165‚Üí}
166‚Üí

  1‚Üípackage email
  2‚Üí
  3‚Üíimport (
  4‚Üí	"database/sql"
  5‚Üí	"encoding/json"
  6‚Üí	"fmt"
  7‚Üí	"strings"
  8‚Üí	"time"
  9‚Üí
 10‚Üí	gm "google.golang.org/api/gmail/v1"
 11‚Üí)
 12‚Üí
 13‚Üítype RawMessage struct {
 14‚Üí	ID          string
 15‚Üí	Source      string
 16‚Üí	Direction   string
 17‚Üí	ThreadID    string
 18‚Üí	Subject     string
 19‚Üí	FromEmail   string
 20‚Üí	ToEmails    string // JSON array
 21‚Üí	CcEmails    string // JSON array
 22‚Üí	Date        string
 23‚Üí	Snippet     string
 24‚Üí	BodyPreview string
 25‚Üí	Labels      string // JSON array
 26‚Üí}
 27‚Üí
 28‚Üítype SyncResult struct {
 29‚Üí	Fetched  int
 30‚Üí	Stored   int
 31‚Üí	Cursor   string
 32‚Üí	Duration time.Duration
 33‚Üí}
 34‚Üí
 35‚Üífunc Sync(srv *gm.Service, d *sql.DB) (*SyncResult, error) {
 36‚Üí	start := time.Now()
 37‚Üí	result := &SyncResult{}
 38‚Üí
 39‚Üí	var cursor string
 40‚Üí	d.QueryRow("SELECT sync_cursor FROM connectors WHERE id = 'gmail'").Scan(&cursor)
 41‚Üí
 42‚Üí	query := "in:sent"
 43‚Üí	if cursor == "" {
 44‚Üí		since := time.Now().AddDate(0, 0, -90).Format("2006/01/02")
 45‚Üí		query += " after:" + since
 46‚Üí	}
 47‚Üí
 48‚Üí	var pageToken string
 49‚Üí	for {
 50‚Üí		req := srv.Users.Messages.List("me").Q(query).MaxResults(100)
 51‚Üí		if pageToken != "" {
 52‚Üí			req = req.PageToken(pageToken)
 53‚Üí		}
 54‚Üí
 55‚Üí		resp, err := req.Do()
 56‚Üí		if err != nil {
 57‚Üí			return result, fmt.Errorf("listing messages: %w", err)
 58‚Üí		}
 59‚Üí
 60‚Üí		for _, msg := range resp.Messages {
 61‚Üí			result.Fetched++
 62‚Üí
 63‚Üí			if cursor != "" {
 64‚Üí				var exists int
 65‚Üí				d.QueryRow("SELECT 1 FROM emails WHERE id = ?", msg.Id).Scan(&exists)
 66‚Üí				if exists == 1 {
 67‚Üí					continue
 68‚Üí				}
 69‚Üí			}
 70‚Üí
 71‚Üí			full, err := srv.Users.Messages.Get("me", msg.Id).Format("metadata").
 72‚Üí				MetadataHeaders("Subject", "From", "To", "Cc", "Date").Do()
 73‚Üí			if err != nil {
 74‚Üí				fmt.Printf("  warning: skipping message %s: %v\n", msg.Id, err)
 75‚Üí				continue
 76‚Üí			}
 77‚Üí
 78‚Üí			email := parseMessage(full)
 79‚Üí			if err := StoreEmail(d, email); err != nil {
 80‚Üí				fmt.Printf("  warning: storing message %s: %v\n", msg.Id, err)
 81‚Üí				continue
 82‚Üí			}
 83‚Üí			result.Stored++
 84‚Üí		}
 85‚Üí
 86‚Üí		pageToken = resp.NextPageToken
 87‚Üí		if pageToken == "" {
 88‚Üí			break
 89‚Üí		}
 90‚Üí	}
 91‚Üí
 92‚Üí	result.Cursor = time.Now().UTC().Format(time.RFC3339)
 93‚Üí	result.Duration = time.Since(start)
 94‚Üí
 95‚Üí	d.Exec(
 96‚Üí		`INSERT INTO connectors (id, type, sync_cursor, last_sync_at, total_synced)
 97‚Üí		 VALUES ('gmail', 'email', ?, ?, ?)
 98‚Üí		 ON CONFLICT(id) DO UPDATE SET sync_cursor = ?, last_sync_at = ?, total_synced = total_synced + ?`,
 99‚Üí		result.Cursor, result.Cursor, result.Stored,
100‚Üí		result.Cursor, result.Cursor, result.Stored,
101‚Üí	)
102‚Üí
103‚Üí	return result, nil
104‚Üí}
105‚Üí
106‚Üífunc StoreEmail(d *sql.DB, e *RawMessage) error {
107‚Üí	source := e.Source
108‚Üí	if source == "" {
109‚Üí		source = "gmail"
110‚Üí	}
111‚Üí	direction := e.Direction
112‚Üí	if direction == "" {
113‚Üí		direction = "outbound"
114‚Üí	}
115‚Üí
116‚Üí	var exists int
117‚Üí	err := d.QueryRow(`SELECT 1 FROM emails WHERE id = ?`, e.ID).Scan(&exists)
118‚Üí	if err != nil && err != sql.ErrNoRows {
119‚Üí		return err
120‚Üí	}
121‚Üí	isNewMessage := err == sql.ErrNoRows
122‚Üí
123‚Üí	_, err = d.Exec(`
124‚Üí		INSERT INTO emails (id, source, direction, thread_id, subject, from_email, to_emails, cc_emails, date, snippet, body_preview, labels)
125‚Üí		VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
126‚Üí		ON CONFLICT(id) DO UPDATE SET
127‚Üí			source = excluded.source,
128‚Üí			direction = excluded.direction,
129‚Üí			subject = excluded.subject,
130‚Üí			snippet = excluded.snippet,
131‚Üí			body_preview = excluded.body_preview,
132‚Üí			labels = excluded.labels,
133‚Üí			synced_at = datetime('now')`,
134‚Üí		e.ID, source, direction, e.ThreadID, e.Subject, e.FromEmail, e.ToEmails, e.CcEmails,
135‚Üí		e.Date, e.Snippet, e.BodyPreview, e.Labels,
136‚Üí	)
137‚Üí	if err != nil {
138‚Üí		return err
139‚Üí	}
140‚Üí	return upsertContactsForMessage(d, source, direction, e, isNewMessage)
141‚Üí}
142‚Üí
143‚Üí// StoreConvexEmails stores emails fetched from Convex into local SQLite.
144‚Üí// Uses the same StoreEmail function as the Gmail API sync path.
145‚Üífunc StoreConvexEmails(d *sql.DB, emails []RawMessage) (*SyncResult, error) {
146‚Üí	start := time.Now()
147‚Üí	result := &SyncResult{Fetched: len(emails)}
148‚Üí
149‚Üí	for _, e := range emails {
150‚Üí		raw := e // copy for pointer
151‚Üí		if err := StoreEmail(d, &raw); err != nil {
152‚Üí			fmt.Printf("  warning: storing email %s: %v\n", e.ID, err)
153‚Üí			continue
154‚Üí		}
155‚Üí		result.Stored++
156‚Üí	}
157‚Üí
158‚Üí	result.Cursor = time.Now().UTC().Format(time.RFC3339)
159‚Üí	result.Duration = time.Since(start)
160‚Üí
161‚Üí	d.Exec(
162‚Üí		`INSERT INTO connectors (id, type, sync_cursor, last_sync_at, total_synced)
163‚Üí		 VALUES ('gmail', 'email', ?, ?, ?)
164‚Üí		 ON CONFLICT(id) DO UPDATE SET sync_cursor = ?, last_sync_at = ?, total_synced = total_synced + ?`,
165‚Üí		result.Cursor, result.Cursor, result.Stored,
166‚Üí		result.Cursor, result.Cursor, result.Stored,
167‚Üí	)
168‚Üí
169‚Üí	return result, nil
170‚Üí}
