172‚Üífunc parseMessage(msg *gm.Message) *RawMessage {
173‚Üí	e := &RawMessage{
174‚Üí		ID:        msg.Id,
175‚Üí		Source:    "gmail",
176‚Üí		Direction: "outbound",
177‚Üí		ThreadID:  msg.ThreadId,
178‚Üí		Snippet:   msg.Snippet,
179‚Üí		CcEmails:  "[]",
180‚Üí		ToEmails:  "[]",
181‚Üí		Labels:    "[]",
182‚Üí	}
183‚Üí
184‚Üí	for _, h := range msg.Payload.Headers {
185‚Üí		switch h.Name {
186‚Üí		case "Subject":
187‚Üí			e.Subject = h.Value
188‚Üí		case "From":
189‚Üí			e.FromEmail = extractEmail(h.Value)
190‚Üí		case "To":
191‚Üí			e.ToEmails = emailsToJSON(h.Value)
192‚Üí		case "Cc":
193‚Üí			e.CcEmails = emailsToJSON(h.Value)
194‚Üí		case "Date":
195‚Üí			if t, err := time.Parse(time.RFC1123Z, h.Value); err == nil {
196‚Üí				e.Date = t.UTC().Format(time.RFC3339)
197‚Üí			} else if t, err := time.Parse("Mon, 2 Jan 2006 15:04:05 -0700", h.Value); err == nil {
198‚Üí				e.Date = t.UTC().Format(time.RFC3339)
199‚Üí			} else {
200‚Üí				e.Date = h.Value
201‚Üí			}
202‚Üí		}
203‚Üí	}
204‚Üí
205‚Üí	if len(msg.LabelIds) > 0 {
206‚Üí		labelsJSON, _ := json.Marshal(msg.LabelIds)
207‚Üí		e.Labels = string(labelsJSON)
208‚Üí	}
209‚Üí
210‚Üí	return e
211‚Üí}
212‚Üí
213‚Üífunc upsertContactsForMessage(d *sql.DB, source, direction string, e *RawMessage, incrementCount bool) error {
214‚Üí	timestamp := e.Date
215‚Üí	if direction == "inbound" {
216‚Üí		return upsertContact(d, source, e.FromEmail, timestamp, incrementCount)
217‚Üí	}
218‚Üí
219‚Üí	recipients := append(parseRecipients(e.ToEmails), parseRecipients(e.CcEmails)...)
220‚Üí	for _, recipient := range recipients {
221‚Üí		if err := upsertContact(d, source, recipient, timestamp, incrementCount); err != nil {
222‚Üí			return err
223‚Üí		}
224‚Üí	}
225‚Üí	return nil
226‚Üí}
227‚Üí
228‚Üífunc upsertContact(d *sql.DB, source, emailAddress, activityAt string, incrementCount bool) error {
229‚Üí	emailAddress = strings.ToLower(strings.TrimSpace(emailAddress))
230‚Üí	if emailAddress == "" {
231‚Üí		return nil
232‚Üí	}
233‚Üí	domain := ""
234‚Üí	parts := strings.SplitN(emailAddress, "@", 2)
235‚Üí	if len(parts) == 2 {
236‚Üí		domain = parts[1]
237‚Üí	}
238‚Üí
239‚Üí	_, err := d.Exec(`
240‚Üí		INSERT INTO contacts (id, source, email, domain, last_activity_at, email_count, last_emailed_at)
241‚Üí		VALUES (?, ?, ?, ?, ?, 1, ?)
242‚Üí		ON CONFLICT(source, email) DO UPDATE SET
243‚Üí			domain = CASE WHEN excluded.domain != '' THEN excluded.domain ELSE contacts.domain END,
244‚Üí			last_activity_at = CASE
245‚Üí				WHEN contacts.last_activity_at = '' OR contacts.last_activity_at IS NULL OR excluded.last_activity_at > contacts.last_activity_at THEN excluded.last_activity_at
246‚Üí				ELSE contacts.last_activity_at
247‚Üí			END,
248‚Üí			last_emailed_at = CASE
249‚Üí				WHEN contacts.last_emailed_at = '' OR contacts.last_emailed_at IS NULL OR excluded.last_emailed_at > contacts.last_emailed_at THEN excluded.last_emailed_at
250‚Üí				ELSE contacts.last_emailed_at
251‚Üí			END,
252‚Üí			email_count = contacts.email_count + ?,
253‚Üí			updated_at = datetime('now')`,
254‚Üí		"contact:"+source+":"+emailAddress, source, emailAddress, domain, activityAt, activityAt, boolToInt(incrementCount),
255‚Üí	)
256‚Üí	return err
257‚Üí}
258‚Üí
259‚Üífunc boolToInt(value bool) int {
260‚Üí	if value {
261‚Üí		return 1
262‚Üí	}
263‚Üí	return 0
264‚Üí}
265‚Üí
266‚Üífunc extractEmail(header string) string {
267‚Üí	if i := strings.Index(header, "<"); i != -1 {
268‚Üí		if j := strings.Index(header, ">"); j != -1 {
269‚Üí			return header[i+1 : j]
270‚Üí		}
271‚Üí	}
272‚Üí	return strings.TrimSpace(header)
273‚Üí}
274‚Üí
275‚Üífunc emailsToJSON(header string) string {
276‚Üí	if header == "" {
277‚Üí		return "[]"
278‚Üí	}
279‚Üí	parts := strings.Split(header, ",")
280‚Üí	emails := make([]string, 0, len(parts))
281‚Üí	for _, p := range parts {
282‚Üí		emails = append(emails, extractEmail(p))
283‚Üí	}
284‚Üí	data, _ := json.Marshal(emails)
285‚Üí	return string(data)
286‚Üí}
