  1‚Üípackage assembly
  2‚Üí
  3‚Üíimport (
  4‚Üí	"database/sql"
  5‚Üí	"fmt"
  6‚Üí	"strings"
  7‚Üí)
  8‚Üí
  9‚Üí// ResumeResult is a compact context snapshot for session hooks (~200 tokens).
 10‚Üítype ResumeResult struct {
 11‚Üí	Summary       string `json:"summary"`
 12‚Üí	TokenEstimate int    `json:"token_estimate"`
 13‚Üí}
 14‚Üí
 15‚Üí// Resume returns a brief working-state summary for compact hook injection.
 16‚Üí// It pulls the most recent assembly task, active prospect, key learnings,
 17‚Üí// and active sequence info into ~200 tokens.
 18‚Üífunc Resume(database *sql.DB) (*ResumeResult, error) {
 19‚Üí	var parts []string
 20‚Üí
 21‚Üí	// Active sequences summary
 22‚Üí	seqSummary, err := activeSequenceSummary(database)
 23‚Üí	if err == nil && seqSummary != "" {
 24‚Üí		parts = append(parts, seqSummary)
 25‚Üí	}
 26‚Üí
 27‚Üí	// Recent learnings (last 3, one-liners)
 28‚Üí	learnings, err := queryLearningsByTypes(database, nil, 3)
 29‚Üí	if err == nil && len(learnings) > 0 {
 30‚Üí		var items []string
 31‚Üí		for _, l := range learnings {
 32‚Üí			// Truncate long learnings
 33‚Üí			content := l.Content
 34‚Üí			if len(content) > 80 {
 35‚Üí				content = content[:77] + "..."
 36‚Üí			}
 37‚Üí			items = append(items, fmt.Sprintf("[%s] %s", l.Type, content))
 38‚Üí		}
 39‚Üí		parts = append(parts, "Learnings: "+strings.Join(items, "; "))
 40‚Üí	}
 41‚Üí
 42‚Üí	// Pending reply events
 43‚Üí	replyCount, err := pendingReplyCount(database)
 44‚Üí	if err == nil && replyCount > 0 {
 45‚Üí		parts = append(parts, fmt.Sprintf("Pending replies: %d", replyCount))
 46‚Üí	}
 47‚Üí
 48‚Üí	// Due follow-ups
 49‚Üí	dueCount, err := dueFollowUpCount(database)
 50‚Üí	if err == nil && dueCount > 0 {
 51‚Üí		parts = append(parts, fmt.Sprintf("Due follow-ups: %d", dueCount))
 52‚Üí	}
 53‚Üí
 54‚Üí	summary := strings.Join(parts, "\n")
 55‚Üí	if summary == "" {
 56‚Üí		summary = "No active context. Start with /nurge:pipeline or /nurge:outbound."
 57‚Üí	}
 58‚Üí
 59‚Üí	return &ResumeResult{
 60‚Üí		Summary:       summary,
 61‚Üí		TokenEstimate: estimateTokens(summary),
 62‚Üí	}, nil
 63‚Üí}
 64‚Üí
 65‚Üí// activeSequenceSummary returns a one-line overview of active sequences.
 66‚Üífunc activeSequenceSummary(database *sql.DB) (string, error) {
 67‚Üí	var activeCount int
 68‚Üí	err := database.QueryRow(`SELECT COUNT(*) FROM sequence_enrollments WHERE status = 'active'`).Scan(&activeCount)
 69‚Üí	if err != nil {
 70‚Üí		return "", err
 71‚Üí	}
 72‚Üí	if activeCount == 0 {
 73‚Üí		return "", nil
 74‚Üí	}
 75‚Üí
 76‚Üí	// Get distinct sequence names
 77‚Üí	rows, err := database.Query(
 78‚Üí		`SELECT sequence_name, COUNT(*) FROM sequence_enrollments WHERE status = 'active' GROUP BY sequence_name LIMIT 5`,
 79‚Üí	)
 80‚Üí	if err != nil {
 81‚Üí		return "", err
 82‚Üí	}
 83‚Üí	defer rows.Close()
 84‚Üí
 85‚Üí	var seqs []string
 86‚Üí	for rows.Next() {
 87‚Üí		var name string
 88‚Üí		var count int
 89‚Üí		if err := rows.Scan(&name, &count); err != nil {
 90‚Üí			continue
 91‚Üí		}
 92‚Üí		seqs = append(seqs, fmt.Sprintf("%s(%d)", name, count))
 93‚Üí	}
 94‚Üí
 95‚Üí	return fmt.Sprintf("Active sequences: %s (total: %d)", strings.Join(seqs, ", "), activeCount), rows.Err()
 96‚Üí}
 97‚Üí
 98‚Üí// pendingReplyCount returns the number of unhandled reply events.
 99‚Üífunc pendingReplyCount(database *sql.DB) (int, error) {
100‚Üí	var count int
101‚Üí	err := database.QueryRow(`SELECT COUNT(*) FROM reply_events WHERE status = 'open'`).Scan(&count)
102‚Üí	return count, err
103‚Üí}
104‚Üí
105‚Üí// dueFollowUpCount returns the number of follow-up tasks due now or overdue.
106‚Üífunc dueFollowUpCount(database *sql.DB) (int, error) {
107‚Üí	var count int
108‚Üí	err := database.QueryRow(
109‚Üí		`SELECT COUNT(*) FROM follow_up_tasks WHERE status = 'open' AND send_status = 'pending' AND due_at <= datetime('now')`,
110‚Üí	).Scan(&count)
111‚Üí	return count, err
112‚Üí}
113‚Üí

