 28‚Üítype SendingPattern struct {
 29‚Üí	MostActiveDay string  `json:"most_active_day"`
 30‚Üí	AvgPerDay     float64 `json:"avg_per_day"`
 31‚Üí	AvgPerWeek    float64 `json:"avg_per_week"`
 32‚Üí}
 33‚Üí
 34‚Üífunc GenerateContext(d *sql.DB) (*Context, error) {
 35‚Üí	ctx := &Context{}
 36‚Üí
 37‚Üí	d.QueryRow("SELECT COUNT(*) FROM emails").Scan(&ctx.TotalEmails)
 38‚Üí	d.QueryRow("SELECT COUNT(*) FROM emails WHERE class = 'outbound'").Scan(&ctx.OutboundCount)
 39‚Üí
 40‚Üí	// Parse to_emails JSON to get actual recipient counts and domain counts
 41‚Üí	recipientCounts := make(map[string]int)
 42‚Üí	domainCounts := make(map[string]int)
 43‚Üí
 44‚Üí	rows, err := d.Query("SELECT to_emails FROM emails WHERE class = 'outbound'")
 45‚Üí	if err == nil {
 46‚Üí		defer rows.Close()
 47‚Üí		for rows.Next() {
 48‚Üí			var toJSON string
 49‚Üí			rows.Scan(&toJSON)
 50‚Üí			var addrs []string
 51‚Üí			if json.Unmarshal([]byte(toJSON), &addrs) == nil {
 52‚Üí				for _, addr := range addrs {
 53‚Üí					recipientCounts[addr]++
 54‚Üí					if parts := strings.SplitN(addr, "@", 2); len(parts) == 2 {
 55‚Üí						domainCounts[parts[1]]++
 56‚Üí					}
 57‚Üí				}
 58‚Üí			}
 59‚Üí		}
 60‚Üí	}
 61‚Üí
 62‚Üí	// Sort by count (top 10)
 63‚Üí	ctx.TopRecipients = topN(recipientCounts, 10, func(k string, v int) RecipientCount {
 64‚Üí		return RecipientCount{Email: k, Count: v}
 65‚Üí	})
 66‚Üí	ctx.TopDomains = topN(domainCounts, 10, func(k string, v int) DomainCount {
 67‚Üí		return DomainCount{Domain: k, Count: v}
 68‚Üí	})
 69‚Üí
 70‚Üí	// Sending pattern
 71‚Üí	d.QueryRow(`
 72‚Üí		SELECT CAST(COUNT(*) AS REAL) / MAX(1, JULIANDAY('now') - JULIANDAY(MIN(date)))
 73‚Üí		FROM emails WHERE class = 'outbound'`).Scan(&ctx.SendingPattern.AvgPerDay)
 74‚Üí	ctx.SendingPattern.AvgPerWeek = ctx.SendingPattern.AvgPerDay * 7
 75‚Üí
 76‚Üí	d.QueryRow(`
 77‚Üí		SELECT CASE CAST(strftime('%w', date) AS INTEGER)
 78‚Üí			WHEN 0 THEN 'Sunday' WHEN 1 THEN 'Monday' WHEN 2 THEN 'Tuesday'
 79‚Üí			WHEN 3 THEN 'Wednesday' WHEN 4 THEN 'Thursday' WHEN 5 THEN 'Friday'
 80‚Üí			WHEN 6 THEN 'Saturday' END
 81‚Üí		FROM emails WHERE class = 'outbound'
 82‚Üí		GROUP BY strftime('%w', date) ORDER BY COUNT(*) DESC LIMIT 1`).Scan(&ctx.SendingPattern.MostActiveDay)
 83‚Üí
 84‚Üí	// Recent outbound subjects
 85‚Üí	subRows, err := d.Query("SELECT subject FROM emails WHERE class = 'outbound' ORDER BY date DESC LIMIT 50")
 86‚Üí	if err == nil {
 87‚Üí		defer subRows.Close()
 88‚Üí		for subRows.Next() {
 89‚Üí			var subj string
 90‚Üí			subRows.Scan(&subj)
 91‚Üí			ctx.CommonSubjects = append(ctx.CommonSubjects, subj)
 92‚Üí		}
 93‚Üí	}
 94‚Üí
 95‚Üí	return ctx, nil
 96‚Üí}
 97‚Üí
 98‚Üífunc topN[T any](counts map[string]int, n int, conv func(string, int) T) []T {
 99‚Üí	type kv struct {
100‚Üí		k string
101‚Üí		v int
102‚Üí	}
103‚Üí	var sorted []kv
104‚Üí	for k, v := range counts {
105‚Üí		sorted = append(sorted, kv{k, v})
106‚Üí	}
107‚Üí	for i := 0; i < len(sorted) && i < n; i++ {
108‚Üí		for j := i + 1; j < len(sorted); j++ {
109‚Üí			if sorted[j].v > sorted[i].v {
110‚Üí				sorted[i], sorted[j] = sorted[j], sorted[i]
111‚Üí			}
112‚Üí		}
113‚Üí	}
114‚Üí	result := make([]T, 0, n)
115‚Üí	for i := 0; i < len(sorted) && i < n; i++ {
116‚Üí		result = append(result, conv(sorted[i].k, sorted[i].v))
117‚Üí	}
118‚Üí	return result
119‚Üí}
120‚Üí

 1‚Üípackage connector
 2‚Üí
 3‚Üíimport (
 4‚Üí	"fmt"
 5‚Üí	"io/fs"
 6‚Üí	"os"
 7‚Üí	"path/filepath"
 8‚Üí	"sort"
 9‚Üí	"strings"
10‚Üí)
11‚Üí
12‚Üí// LoadRegistry scans bundled definitions and project-local definitions,
13‚Üí// returning a merged list. Project-local definitions can override bundled
14‚Üí// Tier 2/3 connectors but NOT Tier 1 (email providers).
15‚Üí// projectDir is the path to .nurge/connectors/definitions/ (empty string to skip).
16‚Üífunc LoadRegistry(projectDir string) ([]ConnectorDef, error) {
17‚Üí	defs := make(map[string]ConnectorDef)
18‚Üí
19‚Üí	// 1. Load bundled definitions
20‚Üí	entries, err := fs.ReadDir(bundledDefinitions, "definitions")
21‚Üí	if err != nil {
22‚Üí		return nil, fmt.Errorf("reading bundled definitions: %w", err)
23‚Üí	}
24‚Üí	for _, entry := range entries {
25‚Üí		if entry.IsDir() || !strings.HasSuffix(entry.Name(), ".yaml") {
26‚Üí			continue
27‚Üí		}
28‚Üí		data, err := bundledDefinitions.ReadFile("definitions/" + entry.Name())
29‚Üí		if err != nil {
30‚Üí			continue
31‚Üí		}
32‚Üí		yamlDef, err := ParseYAML(data)
33‚Üí		if err != nil {
34‚Üí			continue // skip invalid bundled defs
35‚Üí		}
36‚Üí		defs[yamlDef.ID] = ConnectorDef{
37‚Üí			ID:       yamlDef.ID,
38‚Üí			Name:     yamlDef.Name,
39‚Üí			Type:     yamlDef.Type,
40‚Üí			Tier:     yamlDef.Tier,
41‚Üí			Required: yamlDef.Required,
42‚Üí			Def:      yamlDef,
43‚Üí		}
44‚Üí	}
45‚Üí
46‚Üí	// 2. Load project-local definitions (override Tier 2/3 only)
47‚Üí	if projectDir != "" {
48‚Üí		localEntries, err := os.ReadDir(projectDir)
49‚Üí		if err == nil { // silently skip if dir doesn't exist
50‚Üí			for _, entry := range localEntries {
51‚Üí				if entry.IsDir() || !strings.HasSuffix(entry.Name(), ".yaml") {
52‚Üí					continue
53‚Üí				}
54‚Üí				data, err := os.ReadFile(filepath.Join(projectDir, entry.Name()))
55‚Üí				if err != nil {
56‚Üí					continue
57‚Üí				}
58‚Üí				yamlDef, err := ParseYAML(data)
59‚Üí				if err != nil {
60‚Üí					continue
61‚Üí				}
62‚Üí				// Tier 1 connectors cannot be overridden
63‚Üí				if existing, ok := defs[yamlDef.ID]; ok && existing.Tier == 1 {
64‚Üí					fmt.Fprintf(os.Stderr, "warning: project-local definition for %q ignored (Tier 1 connectors cannot be overridden)\n", yamlDef.ID)
65‚Üí					continue
66‚Üí				}
67‚Üí				defs[yamlDef.ID] = ConnectorDef{
68‚Üí					ID:       yamlDef.ID,
69‚Üí					Name:     yamlDef.Name,
70‚Üí					Type:     yamlDef.Type,
71‚Üí					Tier:     yamlDef.Tier,
72‚Üí					Required: yamlDef.Required,
73‚Üí					Def:      yamlDef,
74‚Üí				}
75‚Üí			}
76‚Üí		}
77‚Üí	}
78‚Üí
79‚Üí	// Convert to sorted slice: email first (required), then crm, then enrichment
80‚Üí	typeOrder := map[string]int{"email": 0, "crm": 1, "enrichment": 2, "sequencing": 3, "webhook": 4}
81‚Üí	result := make([]ConnectorDef, 0, len(defs))
82‚Üí	for _, d := range defs {
83‚Üí		result = append(result, d)
84‚Üí	}
85‚Üí	sort.Slice(result, func(i, j int) bool {
86‚Üí		oi := typeOrder[result[i].Type]
87‚Üí		oj := typeOrder[result[j].Type]
88‚Üí		if oi != oj {
89‚Üí			return oi < oj
90‚Üí		}
91‚Üí		return result[i].Name < result[j].Name
92‚Üí	})
93‚Üí
94‚Üí	return result, nil
95‚Üí}
96‚Üí

