  1‚Üíimport { v } from "convex/values";
  2‚Üíimport { httpAction } from "./_generated/server";
  3‚Üíimport { mutation, query } from "./_generated/server";
  4‚Üí
  5‚Üí// Table name mapping: Convex table names (camelCase) ‚Üî SQLite table names (snake_case)
  6‚Üíconst TABLE_MAP: Record<string, string> = {
  7‚Üí  emails: "emails",
  8‚Üí  mailboxes: "mailboxes",
  9‚Üí  mailboxSendEvents: "mailbox_send_events",
 10‚Üí  sequenceEnrollments: "sequence_enrollments",
 11‚Üí  followUpTasks: "follow_up_tasks",
 12‚Üí  suppressions: "suppressions",
 13‚Üí  replyEvents: "reply_events",
 14‚Üí  sequenceDrafts: "sequence_drafts",
 15‚Üí  contacts: "contacts",
 16‚Üí  learnings: "learnings",
 17‚Üí  skillVersions: "skill_versions",
 18‚Üí  deals: "deals",
 19‚Üí};
 20‚Üí
 21‚Üíconst EXECUTION_TABLES = [
 22‚Üí  "emails",
 23‚Üí  "mailboxes",
 24‚Üí  "mailboxSendEvents",
 25‚Üí  "sequenceEnrollments",
 26‚Üí  "followUpTasks",
 27‚Üí  "suppressions",
 28‚Üí  "replyEvents",
 29‚Üí  "sequenceDrafts",
 30‚Üí] as const;
 31‚Üí
 32‚Üí// Pull execution state ‚Äî CLI calls this to mirror Convex ‚Üí SQLite
 33‚Üíexport const pullExecutionState = query({
 34‚Üí  args: {
 35‚Üí    userId: v.string(),
 36‚Üí    syncVersion: v.float64(),
 37‚Üí  },
 38‚Üí  handler: async (ctx, args) => {
 39‚Üí    const rows: Array<{ table: string; id: string; data: Record<string, any>; version: number }> = [];
 40‚Üí
 41‚Üí    for (const table of EXECUTION_TABLES) {
 42‚Üí      const results = await ctx.db
 43‚Üí        .query(table)
 44‚Üí        .withIndex("by_user", (q) => q.eq("userId", args.userId))
 45‚Üí        .filter((q) => q.gt(q.field("syncVersion"), args.syncVersion))
 46‚Üí        .collect();
 47‚Üí
 48‚Üí      for (const row of results) {
 49‚Üí        const { _id, _creationTime, userId, ...data } = row;
 50‚Üí        rows.push({
 51‚Üí          table: TABLE_MAP[table] || table,
 52‚Üí          id: row.externalId as string,
 53‚Üí          data,
 54‚Üí          version: row.syncVersion as number,
 55‚Üí        });
 56‚Üí      }
 57‚Üí    }
 58‚Üí
 59‚Üí    // Find the max sync version across all returned rows
 60‚Üí    let maxVersion = args.syncVersion;
 61‚Üí    for (const row of rows) {
 62‚Üí      if (row.version > maxVersion) {
 63‚Üí        maxVersion = row.version;
 64‚Üí      }
 65‚Üí    }
 66‚Üí
 67‚Üí    return { rows, sync_version: maxVersion };
 68‚Üí  },
 69‚Üí});
 70‚Üí
 71‚Üí// Push local state ‚Äî CLI calls this to push SQLite ‚Üí Convex
 72‚Üíexport const pushLocalState = mutation({
 73‚Üí  args: {
 74‚Üí    userId: v.string(),
 75‚Üí    rows: v.array(
 76‚Üí      v.object({
 77‚Üí        table: v.string(),
 78‚Üí        id: v.string(),
 79‚Üí        data: v.any(),
 80‚Üí      })
 81‚Üí    ),
 82‚Üí  },
 83‚Üí  handler: async (ctx, args) => {
 84‚Üí    const versions: Record<string, number> = {};
 85‚Üí
 86‚Üí    // Get current max sync version
 87‚Üí    const syncState = await ctx.db
 88‚Üí      .query("syncState")
 89‚Üí      .withIndex("by_user", (q) => q.eq("userId", args.userId))
 90‚Üí      .first();
 91‚Üí
 92‚Üí    let currentVersion = syncState?.lastSyncVersion ?? 0;
 93‚Üí
 94‚Üí    // Reverse map: snake_case ‚Üí camelCase
 95‚Üí    const reverseTableMap: Record<string, string> = {};
 96‚Üí    for (const [convex, sqlite] of Object.entries(TABLE_MAP)) {
 97‚Üí      reverseTableMap[sqlite] = convex;
 98‚Üí    }
 99‚Üí
100‚Üí    for (const row of args.rows) {
101‚Üí      const convexTable = reverseTableMap[row.table] || row.table;
102‚Üí      currentVersion++;
103‚Üí
104‚Üí      // Check if row exists
105‚Üí      const existing = await ctx.db
106‚Üí        .query(convexTable as any)
107‚Üí        .withIndex("by_external_id", (q) => q.eq("externalId", row.id))
108‚Üí        .first();
109‚Üí
110‚Üí      const rowData = {
111‚Üí        ...(row.data as Record<string, any>),
112‚Üí        externalId: row.id,
113‚Üí        syncVersion: currentVersion,
114‚Üí        userId: args.userId,
115‚Üí      };
116‚Üí
117‚Üí      if (existing) {
118‚Üí        await ctx.db.patch(existing._id, rowData);
119‚Üí      } else {
120‚Üí        await ctx.db.insert(convexTable as any, rowData);
121‚Üí      }
122‚Üí
123‚Üí      versions[row.id] = currentVersion;
124‚Üí    }
125‚Üí
126‚Üí    // Update sync state
127‚Üí    if (syncState) {
128‚Üí      await ctx.db.patch(syncState._id, { lastSyncVersion: currentVersion });
129‚Üí    } else {
130‚Üí      await ctx.db.insert("syncState", {
131‚Üí        userId: args.userId,
132‚Üí        lastSyncVersion: currentVersion,
133‚Üí      });
134‚Üí    }
135‚Üí
136‚Üí    return { versions };
137‚Üí  },
138‚Üí});
