  4‚Üífunction jsonResponse(data: any, status = 200) {
  5‚Üí  return new Response(JSON.stringify(data), {
  6‚Üí    status,
  7‚Üí    headers: { "Content-Type": "application/json" },
  8‚Üí  });
  9‚Üí}
