 11‚Üíasync function authenticateRequest(ctx: any, request: Request) {
 12‚Üí  const authHeader = request.headers.get("Authorization");
 13‚Üí  if (!authHeader || !authHeader.startsWith("Bearer ")) {
 14‚Üí    return { error: jsonResponse({ error: "Missing auth token" }, 401) };
 15‚Üí  }
 16‚Üí  const token = authHeader.slice(7);
 17‚Üí  const user = await ctx.runQuery(internal.sendApi.findUserByToken, { token });
 18‚Üí  if (!user) {
 19‚Üí    return { error: jsonResponse({ error: "Invalid auth token" }, 401) };
 20‚Üí  }
 21‚Üí  return { user };
 22‚Üí}
 23‚Üí
 24‚Üíasync function getLinkedInAccountIds(ctx: any, userId: string): Promise<string[]> {
 25‚Üí  const accounts = await ctx.runQuery(internal.connect.findAllUnipileAccounts, {
 26‚Üí    userId,
 27‚Üí    provider: "LINKEDIN",
 28‚Üí  });
 29‚Üí  const connected = accounts.filter((a: any) => a.status === "connected");
 30‚Üí  return connected.map((a: any) => a.unipileAccountId);
 31‚Üí}
