 33‚Üíasync function getWorkingLinkedInAccount(ctx: any, userId: string, apiUrl: string, apiKey: string): Promise<string | null> {
 34‚Üí  const ids = await getLinkedInAccountIds(ctx, userId);
 35‚Üí  if (ids.length === 0) return null;
 36‚Üí
 37‚Üí  // Also check Unipile directly for all LinkedIn accounts
 38‚Üí  try {
 39‚Üí    const resp = await fetch(`${apiUrl}/api/v1/accounts`, {
 40‚Üí      headers: { "X-API-KEY": apiKey },
 41‚Üí    });
 42‚Üí    if (resp.ok) {
 43‚Üí      const data = await resp.json();
 44‚Üí      const linkedinAccounts = (data.items || [])
 45‚Üí        .filter((a: any) => a.type === "LINKEDIN" && a.sources?.[0]?.status === "OK")
 46‚Üí        .map((a: any) => a.id);
 47‚Üí      // Return first account that's both in Convex and active in Unipile
 48‚Üí      for (const id of linkedinAccounts) {
 49‚Üí        return id; // Use the first active one from Unipile
 50‚Üí      }
 51‚Üí    }
 52‚Üí  } catch (e) {
 53‚Üí    // Fall through to Convex accounts
 54‚Üí  }
 55‚Üí
 56‚Üí  return ids[0]; // fallback to first Convex account
 57‚Üí}
