 86‚Üí// POST /api/enrich-company ‚Äî get company profile + all employees via Unipile
 87‚Üíexport const enrichCompany = httpAction(async (ctx, request) => {
 88‚Üí  try {
 89‚Üí    const auth = await authenticateRequest(ctx, request);
 90‚Üí    if (auth.error) return auth.error;
 91‚Üí    const user = auth.user!;
 92‚Üí
 93‚Üí    const payload = await request.json();
 94‚Üí    const slug = payload.slug || "";
 95‚Üí    if (!slug) return jsonResponse({ error: "Missing slug" }, 400);
 96‚Üí
 97‚Üí    const apiKey = process.env.UNIPILE_API_KEY;
 98‚Üí    const apiUrl = process.env.UNIPILE_API_URL;
 99‚Üí    if (!apiKey || !apiUrl) return jsonResponse({ error: "Unipile not configured" }, 500);
100‚Üí
101‚Üí    const accountId = await getWorkingLinkedInAccount(ctx, user._id, apiUrl, apiKey);
102‚Üí    if (!accountId) return jsonResponse({ error: "LinkedIn not connected. Run: nurge connect linkedin" }, 400);
