138‚Üí        activities: company.activities || [],
139‚Üí        hashtags: (company.hashtags || []).map((h: any) => h.title || h),
140‚Üí        logo: company.logo || "",
141‚Üí      },
142‚Üí      employees: employees.map((p: any) => ({
143‚Üí        name: p.name || "",
144‚Üí        headline: p.headline || "",
145‚Üí        location: p.location || "",
146‚Üí        linkedin_id: p.public_identifier || "",
