244‚Üí
245‚Üí    return jsonResponse({
246‚Üí      items: allItems.map((p: any) => ({
247‚Üí        name: p.name || "",
248‚Üí        headline: p.headline || "",
249‚Üí        location: p.location || "",
250‚Üí        linkedin_id: p.public_identifier || "",
