 12‚Üí// getContact queries the contacts table by email.
 13‚Üífunc getContact(database *sql.DB, email string) (*Contact, error) {
 14‚Üí	var c Contact
 15‚Üí	err := database.QueryRow(`
 16‚Üí		SELECT id, source, email, name, domain, company, title, phone,
 17‚Üí			   lead_status, tier, tier_score, industry, funding_stage,
 18‚Üí			   company_size, linkedin_url, signals, tech_stack,
 19‚Üí			   data_confidence, resolve_source, enriched_at, enrichment_sources
 20‚Üí		FROM contacts WHERE email = ?
 21‚Üí	`, email).Scan(
 22‚Üí		&c.ID, &c.Source, &c.Email, &c.Name, &c.Domain, &c.Company, &c.Title, &c.Phone,
 23‚Üí		&c.LeadStatus, &c.Tier, &c.TierScore, &c.Industry, &c.FundingStage,
 24‚Üí		&c.CompanySize, &c.LinkedInURL, &c.Signals, &c.TechStack,
 25‚Üí		&c.DataConfidence, &c.ResolveSource, &c.EnrichedAt, &c.EnrichmentSources,
 26‚Üí	)
 27‚Üí	if err == sql.ErrNoRows {
 28‚Üí		return nil, nil
 29‚Üí	}
 30‚Üí	if err != nil {
 31‚Üí		return nil, err
 32‚Üí	}
 33‚Üí	return &c, nil
 34‚Üí}
