 36‚Üí// buildScopes derives the atom lookup scopes from a contact.
 37‚Üí// More specific scopes come first; QueryAtoms returns best match.
 38‚Üífunc buildScopes(contact *Contact) []string {
 39‚Üí	if contact == nil {
 40‚Üí		return nil
 41‚Üí	}
 42‚Üí	var scopes []string
 43‚Üí	// Persona/title scope
 44‚Üí	if contact.Title != "" {
 45‚Üí		scopes = append(scopes, normalizeScope(contact.Title))
 46‚Üí	}
 47‚Üí	// Tier scope
 48‚Üí	if contact.Tier > 0 {
 49‚Üí		scopes = append(scopes, fmt.Sprintf("tier_%d", contact.Tier))
 50‚Üí	}
 51‚Üí	// Industry scope
 52‚Üí	if contact.Industry != "" {
 53‚Üí		scopes = append(scopes, normalizeScope(contact.Industry))
 54‚Üí	}
 55‚Üí	// Domain scope (for company-specific atoms)
 56‚Üí	if contact.Domain != "" {
 57‚Üí		scopes = append(scopes, contact.Domain)
 58‚Üí	}
 59‚Üí	return scopes
 60‚Üí}
 61‚Üí
 62‚Üí// normalizeScope lowercases and trims for consistent matching.
 63‚Üífunc normalizeScope(s string) string {
 64‚Üí	return strings.ToLower(strings.TrimSpace(s))
 65‚Üí}
