110‚Üí// pickBestAtom selects the most relevant atom from candidates.
111‚Üí// It prefers scoped matches over the global fallback. Among scoped matches,
112‚Üí// it picks the one whose scope appears earliest in the scopes list
113‚Üí// (most specific first). Falls back to confidence/recency ordering.
114‚Üífunc pickBestAtom(atoms []KnowledgeAtom, scopes []string) KnowledgeAtom {
115‚Üí	if len(atoms) == 1 {
116‚Üí		return atoms[0]
117‚Üí	}
118‚Üí
119‚Üí	// Build scope priority: lower index = higher priority
120‚Üí	scopePrio := make(map[string]int, len(scopes))
121‚Üí	for i, s := range scopes {
122‚Üí		scopePrio[s] = i
123‚Üí	}
124‚Üí
125‚Üí	best := atoms[0]
126‚Üí	bestPrio := len(scopes) + 1 // global ("") gets worst priority
127‚Üí	if p, ok := scopePrio[best.Scope]; ok {
128‚Üí		bestPrio = p
129‚Üí	}
130‚Üí
131‚Üí	for _, a := range atoms[1:] {
132‚Üí		prio := len(scopes) + 1
133‚Üí		if p, ok := scopePrio[a.Scope]; ok {
134‚Üí			prio = p
135‚Üí		}
136‚Üí		if prio < bestPrio {
137‚Üí			best = a
138‚Üí			bestPrio = prio
139‚Üí		}
140‚Üí	}
141‚Üí	return best
142‚Üí}
