  1‚Üípackage assembly
  2‚Üí
  3‚Üíimport (
  4‚Üí	"database/sql"
  5‚Üí	"fmt"
  6‚Üí	"strings"
  7‚Üí)
  8‚Üí
  9‚Üí// Assemble builds the context prompt for a given task and optional prospect.
 10‚Üífunc Assemble(database *sql.DB, req AssembleRequest) (*AssembleResult, error) {
 11‚Üí	if !ValidTaskTypes[req.Task] {
 12‚Üí		return nil, fmt.Errorf("unknown task type: %s", req.Task)
 13‚Üí	}
 14‚Üí	if req.Format == "" {
 15‚Üí		req.Format = "markdown"
 16‚Üí	}
 17‚Üí
 18‚Üí	// Check in-memory cache
 19‚Üí	cacheKey := string(req.Task) + ":" + req.Prospect
 20‚Üí	if cached, ok := defaultCache.Get(cacheKey); ok {
 21‚Üí		return &AssembleResult{
 22‚Üí			Context:       cached,
 23‚Üí			TokenEstimate: estimateTokens(cached),
 24‚Üí			Cached:        true,
 25‚Üí		}, nil
 26‚Üí	}
 27‚Üí
 28‚Üí	var sections []section
 29‚Üí	var atomsLoaded []string
 30‚Üí	var directives []string
 31‚Üí
 32‚Üí	// Load prospect info if applicable
 33‚Üí	var contact *Contact
 34‚Üí	if req.Prospect != "" {
 35‚Üí		c, err := getContact(database, req.Prospect)
 36‚Üí		if err != nil {
 37‚Üí			return nil, fmt.Errorf("querying contact: %w", err)
 38‚Üí		}
 39‚Üí		contact = c
 40‚Üí	}
 41‚Üí
 42‚Üí	// Build prospect context section
 43‚Üí	if contact != nil {
 44‚Üí		sections = append(sections, section{
 45‚Üí			heading: "Context",
 46‚Üí			body:    formatContact(contact),
 47‚Üí		})
 48‚Üí	} else if req.Prospect != "" && prospectTasks[req.Task] {
 49‚Üí		// Prospect specified but not found -- directive to enrich
 50‚Üí		sections = append(sections, section{
 51‚Üí			heading: "Context",
 52‚Üí			body:    fmt.Sprintf("Prospect: %s (not in contacts -- limited context available)", req.Prospect),
 53‚Üí		})
 54‚Üí		directives = append(directives, "enrich_required: contact not found in database, run nurge resolve to enrich")
 55‚Üí	}
 56‚Üí
 57‚Üí	// Determine scopes for atom queries based on contact
 58‚Üí	scopes := buildScopes(contact)
 59‚Üí
 60‚Üí	// Load atoms for this task type
 61‚Üí	neededAtoms := taskAtomMap[req.Task]
 62‚Üí	for _, atomType := range neededAtoms {
 63‚Üí		atoms, err := QueryAtoms(database, atomType, scopes...)
 64‚Üí		if err != nil {
 65‚Üí			return nil, fmt.Errorf("querying %s atoms: %w", atomType, err)
 66‚Üí		}
 67‚Üí		if len(atoms) > 0 {
 68‚Üí			best := pickBestAtom(atoms, scopes)
 69‚Üí			content := extractContent(best.Content)
 70‚Üí			heading := atomHeading(atomType)
 71‚Üí			sections = append(sections, section{heading: heading, body: content})
 72‚Üí			atomsLoaded = append(atomsLoaded, fmt.Sprintf("%s/%s", best.AtomType, best.Scope))
 73‚Üí			// Touch the atom to track usage
 74‚Üí			_ = TouchAtom(database, best.ID)
 75‚Üí		}
 76‚Üí	}
 77‚Üí
 78‚Üí	// Research dossier for prospect-facing tasks
 79‚Üí	if req.Prospect != "" && prospectTasks[req.Task] {
 80‚Üí		dossier, err := GetDossier(database, req.Prospect)
 81‚Üí		if err != nil {
 82‚Üí			return nil, fmt.Errorf("getting dossier: %w", err)
 83‚Üí		}
 84‚Üí		if dossier != nil {
 85‚Üí			content := extractContent(dossier.Dossier)
 86‚Üí			sections = append(sections, section{heading: "Research", body: content})
 87‚Üí		} else if contact != nil && contact.Tier > 0 && contact.Tier <= 2 {
 88‚Üí			directives = append(directives, "research_required: Tier 1/2 prospect has no research dossier -- run /nurge:research first")
 89‚Üí		}
 90‚Üí	}
 91‚Üí
 92‚Üí	// Check for empty enrichment fields on known contacts
 93‚Üí	if contact != nil && contact.EnrichedAt == "" && prospectTasks[req.Task] {
 94‚Üí		directives = append(directives, "enrich_required: contact has not been enriched -- run nurge resolve to fill in company, title, and signals")
 95‚Üí	}
 96‚Üí
 97‚Üí	// Load recent relevant learnings
 98‚Üí	learnings, err := queryRecentLearnings(database, req.Task, 10)
 99‚Üí	if err != nil {
100‚Üí		return nil, fmt.Errorf("querying learnings: %w", err)
101‚Üí	}
102‚Üí	if len(learnings) > 0 {
103‚Üí		var lines []string
104‚Üí		for _, l := range learnings {
105‚Üí			lines = append(lines, fmt.Sprintf("- [%s] %s", l.Type, l.Content))
106‚Üí		}
107‚Üí		sections = append(sections, section{heading: "Recent Learnings", body: strings.Join(lines, "\n")})
108‚Üí	}
109‚Üí
110‚Üí	// Load config context
111‚Üí	cfgSection := loadConfigContext(req.Task)
112‚Üí	if cfgSection != "" {
113‚Üí		sections = append(sections, section{heading: "Configuration", body: cfgSection})
114‚Üí	}
115‚Üí
116‚Üí	// Directives section (placed early so the skill sees it first)
117‚Üí	var result strings.Builder
118‚Üí	if len(directives) > 0 {
119‚Üí		result.WriteString("## Directives\n")
120‚Üí		for _, d := range directives {
121‚Üí			result.WriteString(fmt.Sprintf("- %s\n", d))
122‚Üí		}
123‚Üí		result.WriteString("\n")
124‚Üí	}
125‚Üí
126‚Üí	// Render remaining sections
127‚Üí	for _, s := range sections {
128‚Üí		result.WriteString(fmt.Sprintf("## %s\n%s\n\n", s.heading, s.body))
129‚Üí	}
130‚Üí
131‚Üí	context := strings.TrimSpace(result.String())
132‚Üí
133‚Üí	// Cache the result
134‚Üí	defaultCache.Set(cacheKey, context)
135‚Üí
136‚Üí	return &AssembleResult{
137‚Üí		Context:       context,
138‚Üí		TokenEstimate: estimateTokens(context),
139‚Üí		AtomsLoaded:   atomsLoaded,
140‚Üí		Directives:    directives,
141‚Üí		Cached:        false,
142‚Üí	}, nil
143‚Üí}
144‚Üí
145‚Üí// InvalidateCache clears the in-memory assembly cache.
146‚Üífunc InvalidateCache() {
147‚Üí	defaultCache.Invalidate()
148‚Üí}
149‚Üí

