 30‚Üí
 31‚Üí// NewHubSpot creates a new HubSpot connector.
 32‚Üífunc NewHubSpot(credentials string) Connector {
 33‚Üí	return &hubspotConnector{credentials: credentials}
 34‚Üí}
 35‚Üí
 36‚Üífunc (h *hubspotConnector) ID() string   { return "hubspot" }
 37‚Üífunc (h *hubspotConnector) Name() string { return "HubSpot" }
 38‚Üífunc (h *hubspotConnector) Type() string { return "crm" }
 39‚Üí
 40‚Üífunc (h *hubspotConnector) Connect(ctx context.Context) (*Result, error) {
 41‚Üí	// HubSpot OAuth client credentials
 42‚Üí	// These come from the HubSpot developer app settings
 43‚Üí	clientID := os.Getenv("NURGE_HUBSPOT_CLIENT_ID")
 44‚Üí	clientSecret := os.Getenv("NURGE_HUBSPOT_CLIENT_SECRET")
 45‚Üí
 46‚Üí	if clientID == "" || clientSecret == "" {
 47‚Üí		return nil, fmt.Errorf("HubSpot credentials not configured.\n  Set NURGE_HUBSPOT_CLIENT_ID and NURGE_HUBSPOT_CLIENT_SECRET environment variables.\n  Create a HubSpot app at https://developers.hubspot.com/")
 48‚Üí	}
 49‚Üí
 50‚Üí	oauthCfg := &oauth2.Config{
 51‚Üí		ClientID:     clientID,
 52‚Üí		ClientSecret: clientSecret,
 53‚Üí		Scopes:       hubspotScopes,
 54‚Üí		Endpoint: oauth2.Endpoint{
 55‚Üí			AuthURL:  hubspotAuthURL,
 56‚Üí			TokenURL: hubspotTokenURL,
 57‚Üí		},
 58‚Üí	}
 59‚Üí
 60‚Üí	// Run shared OAuth flow
 61‚Üí	token, err := OAuthFlow(ctx, oauthCfg)
 62‚Üí	if err != nil {
 63‚Üí		return nil, err
 64‚Üí	}
 65‚Üí
 66‚Üí	// Save token
 67‚Üí	if err := os.MkdirAll(".nurge/connectors/hubspot", 0755); err != nil {
 68‚Üí		return nil, fmt.Errorf("creating hubspot connector dir: %w", err)
 69‚Üí	}
 70‚Üí	if err := saveToken(hubspotTokenPath, token); err != nil {
 71‚Üí		return nil, fmt.Errorf("saving token: %w", err)
 72‚Üí	}
 73‚Üí
 74‚Üí	// Get account info
 75‚Üí	account, err := getHubSpotAccount(ctx, oauthCfg, token)
 76‚Üí	if err != nil {
 77‚Üí		// Non-fatal ‚Äî we're connected, just can't get the display name
 78‚Üí		account = "connected"
 79‚Üí	}
 80‚Üí
 81‚Üí	return &Result{
 82‚Üí		Account: account,
 83‚Üí		Token:   token,
 84‚Üí	}, nil
 85‚Üí}
 86‚Üí
 87‚Üí// getHubSpotAccount fetches the portal name or account info.
 88‚Üífunc getHubSpotAccount(ctx context.Context, cfg *oauth2.Config, token *oauth2.Token) (string, error) {
 89‚Üí	client := cfg.Client(ctx, token)
 90‚Üí
 91‚Üí	// Get access token info which includes the hub domain
 92‚Üí	req, err := http.NewRequestWithContext(ctx, "GET",
 93‚Üí		fmt.Sprintf("https://api.hubapi.com/oauth/v1/access-tokens/%s", token.AccessToken), nil)
 94‚Üí	if err != nil {
 95‚Üí		return "", err
 96‚Üí	}
 97‚Üí
 98‚Üí	resp, err := client.Do(req)
 99‚Üí	if err != nil {
100‚Üí		return "", err
101‚Üí	}
102‚Üí	defer resp.Body.Close()
103‚Üí
104‚Üí	if resp.StatusCode != 200 {
105‚Üí		return "", fmt.Errorf("HubSpot API returned %d", resp.StatusCode)
106‚Üí	}
107‚Üí
108‚Üí	var info struct {
109‚Üí		HubDomain string `json:"hub_domain"`
110‚Üí		HubID     int    `json:"hub_id"`
111‚Üí		User      string `json:"user"`
112‚Üí	}
113‚Üí	if err := json.NewDecoder(resp.Body).Decode(&info); err != nil {
114‚Üí		return "", err
115‚Üí	}
116‚Üí
117‚Üí	if info.HubDomain != "" {
118‚Üí		return info.HubDomain, nil
119‚Üí	}
120‚Üí	return fmt.Sprintf("hub-%d", info.HubID), nil
121‚Üí}
