 1‚Üípackage email
 2‚Üí
 3‚Üíimport (
 4‚Üí	"encoding/base64"
 5‚Üí	"fmt"
 6‚Üí	"strings"
 7‚Üí
 8‚Üí	gm "google.golang.org/api/gmail/v1"
 9‚Üí)
10‚Üí
11‚Üí// SendOptions holds the fields for composing an email.
12‚Üítype SendOptions struct {
13‚Üí	To       string // recipient email
14‚Üí	Cc       string // optional CC
15‚Üí	Subject  string
16‚Üí	Body     string // plain text body
17‚Üí	ThreadID string
18‚Üí}
19‚Üí
20‚Üítype SentMessage struct {
21‚Üí	MessageID string
22‚Üí	ThreadID  string
23‚Üí}
24‚Üí
25‚Üí// Send sends an email via the Gmail API.
26‚Üífunc Send(srv *gm.Service, from string, opts SendOptions) (*SentMessage, error) {
27‚Üí	if opts.To == "" {
28‚Üí		return nil, fmt.Errorf("recipient (--to) is required")
29‚Üí	}
30‚Üí	if opts.Subject == "" {
31‚Üí		return nil, fmt.Errorf("subject (--subject) is required")
32‚Üí	}
33‚Üí	if opts.Body == "" {
34‚Üí		return nil, fmt.Errorf("body (--body) is required")
35‚Üí	}
36‚Üí
37‚Üí	raw := buildRawMessage(from, opts)
38‚Üí	msg := &gm.Message{
39‚Üí		Raw: base64.URLEncoding.EncodeToString([]byte(raw)),
40‚Üí	}
41‚Üí	if opts.ThreadID != "" {
42‚Üí		msg.ThreadId = opts.ThreadID
43‚Üí	}
44‚Üí
45‚Üí	sent, err := srv.Users.Messages.Send("me", msg).Do()
46‚Üí	if err != nil {
47‚Üí		return nil, fmt.Errorf("sending email: %w", err)
48‚Üí	}
49‚Üí
50‚Üí	return &SentMessage{
51‚Üí		MessageID: sent.Id,
52‚Üí		ThreadID:  sent.ThreadId,
53‚Üí	}, nil
54‚Üí}
55‚Üí
56‚Üífunc buildRawMessage(from string, opts SendOptions) string {
57‚Üí	var b strings.Builder
58‚Üí	b.WriteString("From: " + from + "\r\n")
59‚Üí	b.WriteString("To: " + opts.To + "\r\n")
60‚Üí	if opts.Cc != "" {
61‚Üí		b.WriteString("Cc: " + opts.Cc + "\r\n")
62‚Üí	}
63‚Üí	b.WriteString("Subject: " + opts.Subject + "\r\n")
64‚Üí	b.WriteString("MIME-Version: 1.0\r\n")
65‚Üí	b.WriteString("Content-Type: text/plain; charset=\"UTF-8\"\r\n")
66‚Üí	b.WriteString("\r\n")
67‚Üí	b.WriteString(opts.Body)
68‚Üí	return b.String()
69‚Üí}
