  1‚Üípackage email
  2‚Üí
  3‚Üíimport (
  4‚Üí	"database/sql"
  5‚Üí	"strings"
  6‚Üí	"time"
  7‚Üí
  8‚Üí	gm "google.golang.org/api/gmail/v1"
  9‚Üí
 10‚Üí	"github.com/usenurge/nurgesh/internal/sequence"
 11‚Üí)
 12‚Üí
 13‚Üítype ReplySyncResult struct {
 14‚Üí	ThreadsScanned  int `json:"threads_scanned"`
 15‚Üí	MessagesScanned int `json:"messages_scanned"`
 16‚Üí	RepliesRecorded int `json:"replies_recorded"`
 17‚Üí	Paused          int `json:"paused"`
 18‚Üí	Stopped         int `json:"stopped"`
 19‚Üí}
 20‚Üí
 21‚Üífunc SyncReplies(srv *gm.Service, d *sql.DB, mailboxEmail string, now time.Time) (*ReplySyncResult, error) {
 22‚Üí	if now.IsZero() {
 23‚Üí		now = time.Now()
 24‚Üí	}
 25‚Üí
 26‚Üí	enrollments, err := sequence.ListEnrollments(d, sequence.StatusActive, 0)
 27‚Üí	if err != nil {
 28‚Üí		return nil, err
 29‚Üí	}
 30‚Üí
 31‚Üí	result := &ReplySyncResult{}
 32‚Üí	for _, enrollment := range enrollments {
 33‚Üí		if enrollment.ThreadID == "" {
 34‚Üí			continue
 35‚Üí		}
 36‚Üí		if mailboxEmail != "" && !strings.EqualFold(mailboxEmail, enrollment.MailboxEmail) {
 37‚Üí			continue
 38‚Üí		}
 39‚Üí
 40‚Üí		thread, err := srv.Users.Threads.Get("me", enrollment.ThreadID).Format("metadata").
 41‚Üí			MetadataHeaders("Subject", "From", "To", "Cc", "Date").Do()
 42‚Üí		if err != nil {
 43‚Üí			return nil, err
 44‚Üí		}
 45‚Üí		result.ThreadsScanned++
 46‚Üí
 47‚Üí		watermark := latestKnownThreadTime(enrollment)
 48‚Üí		for i := 0; i < len(thread.Messages); i++ {
 49‚Üí			result.MessagesScanned++
 50‚Üí			raw := parseMessage(thread.Messages[i])
 51‚Üí			raw.Direction = inferDirection(raw, enrollment.MailboxEmail)
 52‚Üí			if raw.Direction != "inbound" {
 53‚Üí				continue
 54‚Üí			}
 55‚Üí
 56‚Üí			occurredAt, ok := parseStoredEmailTime(raw.Date)
 57‚Üí			if !ok {
 58‚Üí				continue
 59‚Üí			}
 60‚Üí			if !watermark.IsZero() && !occurredAt.After(watermark) {
 61‚Üí				continue
 62‚Üí			}
 63‚Üí
 64‚Üí			raw.ThreadID = enrollment.ThreadID
 65‚Üí			raw.Direction = "inbound"
 66‚Üí			if err := StoreEmail(d, raw); err != nil {
 67‚Üí				return nil, err
 68‚Üí			}
 69‚Üí
 70‚Üí			reply, err := sequence.RecordReply(d, sequence.ReplyOptions{
 71‚Üí				EnrollmentID:   enrollment.ID,
 72‚Üí				MailboxID:      enrollment.MailboxID,
 73‚Üí				ThreadID:       enrollment.ThreadID,
 74‚Üí				MessageID:      raw.ID,
 75‚Üí				ContactEmail:   raw.FromEmail,
 76‚Üí				Classification: classifyReply(raw.FromEmail, raw.Subject, raw.Snippet),
 77‚Üí				Subject:        raw.Subject,
 78‚Üí				Snippet:        raw.Snippet,
 79‚Üí				OccurredAt:     occurredAt,
 80‚Üí			})
 81‚Üí			if err != nil {
 82‚Üí				return nil, err
 83‚Üí			}
 84‚Üí
 85‚Üí			result.RepliesRecorded++
 86‚Üí			if reply.Classification == "not_interested" || reply.Classification == "unsubscribe" || reply.Classification == "bounced" {
 87‚Üí				result.Stopped++
 88‚Üí			} else {
 89‚Üí				result.Paused++
 90‚Üí			}
 91‚Üí		}
 92‚Üí	}
 93‚Üí
 94‚Üí	return result, nil
 95‚Üí}
 96‚Üí
 97‚Üífunc classifyReply(fromEmail, subject, snippet string) string {
 98‚Üí	text := strings.ToLower(strings.TrimSpace(fromEmail) + "\n" + subject + "\n" + snippet)
 99‚Üí	switch {
100‚Üí	case containsAny(text, "mailer-daemon", "postmaster", "delivery status notification", "undeliverable", "message blocked", "delivery has failed"):
101‚Üí		return "bounced"
102‚Üí	case containsAny(text, "out of office", "out-of-office", "automatic reply", "auto-reply", "ooo", "away until"):
103‚Üí		return "out_of_office"
104‚Üí	case containsAny(text, "unsubscribe", "stop emailing", "do not contact"):
105‚Üí		return "unsubscribe"
106‚Üí	case containsAny(text, "not interested", "no interest", "no thanks", "remove me"):
107‚Üí		return "not_interested"
108‚Üí	case containsAny(text, "yes", "interested", "sounds good", "let's chat", "let us chat", "worth a look", "happy to talk"):
109‚Üí		return "interested"
110‚Üí	case containsAny(text, "reach out to", "talk to", "speak with", "contact ") && strings.Contains(text, "@"):
111‚Üí		return "referral"
112‚Üí	default:
113‚Üí		return "replied"
114‚Üí	}
115‚Üí}
116‚Üí
117‚Üífunc latestKnownThreadTime(enrollment sequence.Enrollment) time.Time {
118‚Üí	candidates := []string{enrollment.LastReplyAt, enrollment.LastSentAt}
119‚Üí	for _, candidate := range candidates {
120‚Üí		if candidate == "" {
121‚Üí			continue
122‚Üí		}
123‚Üí		if ts, err := time.Parse(time.RFC3339, candidate); err == nil {
124‚Üí			return ts.UTC()
125‚Üí		}
126‚Üí	}
127‚Üí	return time.Time{}
128‚Üí}
129‚Üí
130‚Üífunc inferDirection(message *RawMessage, mailboxEmail string) string {
131‚Üí	if mailboxEmail != "" && strings.EqualFold(strings.TrimSpace(message.FromEmail), strings.TrimSpace(mailboxEmail)) {
132‚Üí		return "outbound"
133‚Üí	}
134‚Üí	return "inbound"
135‚Üí}
136‚Üí
137‚Üífunc containsAny(text string, needles ...string) bool {
138‚Üí	for _, needle := range needles {
139‚Üí		if strings.Contains(text, needle) {
140‚Üí			return true
141‚Üí		}
142‚Üí	}
143‚Üí	return false
144‚Üí}
145‚Üí

