 14‚Üívar (
 15‚Üí	sendTo          string
 16‚Üí	sendCc          string
 17‚Üí	sendSubject     string
 18‚Üí	sendBody        string
 19‚Üí	sendSequence    string
 20‚Üí	sendCampaign    string
