  1‚Üípackage seq
  2‚Üí
  3‚Üíimport (
  4‚Üí	"database/sql"
  5‚Üí	"fmt"
  6‚Üí	"strings"
  7‚Üí	"time"
  8‚Üí
  9‚Üí	"github.com/usenurge/nurgesh/cmd/cmdutil"
 10‚Üí	"github.com/usenurge/nurgesh/internal/email"
 11‚Üí	"github.com/usenurge/nurgesh/internal/sequence"
 12‚Üí	gm "google.golang.org/api/gmail/v1"
 13‚Üí)
 14‚Üí
 15‚Üífunc executeDispatch(srv *gm.Service, d *sql.DB, dispatch []sequence.DispatchTask) ([]dispatcherExecutionResult, error) {
 16‚Üí	results := make([]dispatcherExecutionResult, 0, len(dispatch))
 17‚Üí	for _, item := range dispatch {
 18‚Üí		if !item.Ready {
 19‚Üí			continue
 20‚Üí		}
 21‚Üí
 22‚Üí		attemptedAt := time.Now()
 23‚Üí		fromAddress := strings.TrimSpace(item.TransportEmail)
 24‚Üí		if fromAddress == "" {
 25‚Üí			fromAddress = strings.TrimSpace(item.SelectedMailboxEmail)
 26‚Üí		}
 27‚Üí		if fromAddress == "" {
 28‚Üí			results = append(results, dispatcherExecutionResult{
 29‚Üí				TaskID:       item.ID,
 30‚Üí				ContactEmail: item.ContactEmail,
 31‚Üí				MailboxEmail: item.SelectedMailboxEmail,
 32‚Üí				Status:       "failed",
 33‚Üí				Error:        "no transport address available for task",
 34‚Üí			})
 35‚Üí			continue
 36‚Üí		}
 37‚Üí
 38‚Üí		sent, err := email.Send(srv, fromAddress, email.SendOptions{
 39‚Üí			To:       item.ContactEmail,
 40‚Üí			Subject:  dispatchSubject(item),
 41‚Üí			Body:     item.RenderedBody,
 42‚Üí			ThreadID: item.ThreadID,
 43‚Üí		})
 44‚Üí		if err != nil {
 45‚Üí			if markErr := sequence.MarkTaskAttempt(d, item.ID, attemptedAt, err); markErr != nil {
 46‚Üí				return results, markErr
 47‚Üí			}
 48‚Üí			if updateErr := sequence.UpdateTaskSendState(d, item.ID, sequence.TaskSendStatusFailed, "", "", err.Error()); updateErr != nil {
 49‚Üí				return results, updateErr
 50‚Üí			}
 51‚Üí			if logErr := sequence.LogSendAttempt(d, sequence.SendAttemptOptions{
 52‚Üí				MailboxID:    item.SelectedMailboxID,
 53‚Üí				EnrollmentID: item.EnrollmentID,
 54‚Üí				TaskID:       item.ID,
 55‚Üí				ContactEmail: item.ContactEmail,
 56‚Üí				SendType:     item.SendType,
 57‚Üí				Status:       "failed",
 58‚Üí				Subject:      dispatchSubject(item),
 59‚Üí				Error:        err.Error(),
 60‚Üí				AttemptedAt:  attemptedAt,
 61‚Üí			}); logErr != nil {
 62‚Üí				return results, logErr
 63‚Üí			}
 64‚Üí			results = append(results, dispatcherExecutionResult{
 65‚Üí				TaskID:       item.ID,
 66‚Üí				ContactEmail: item.ContactEmail,
 67‚Üí				MailboxEmail: item.SelectedMailboxEmail,
 68‚Üí				Status:       "failed",
 69‚Üí				Error:        err.Error(),
 70‚Üí			})
 71‚Üí			continue
 72‚Üí		}
 73‚Üí
 74‚Üí		if err := sequence.MarkTaskAttempt(d, item.ID, attemptedAt, nil); err != nil {
 75‚Üí			return results, err
 76‚Üí		}
 77‚Üí		if err := sequence.UpdateTaskSendState(d, item.ID, sequence.TaskSendStatusSent, sent.MessageID, "", ""); err != nil {
 78‚Üí			return results, err
 79‚Üí		}
 80‚Üí		if err := sequence.RecordSend(d, item.SelectedMailboxID, item.SendType, attemptedAt); err != nil {
 81‚Üí			return results, fmt.Errorf("email sent (message ID: %s) but failed to record mailbox usage: %w", sent.MessageID, err)
 82‚Üí		}
 83‚Üí		if err := email.StoreEmail(d, &email.RawMessage{
 84‚Üí			ID:        sent.MessageID,
 85‚Üí			Source:    "gmail",
 86‚Üí			Direction: "outbound",
 87‚Üí			ThreadID:  sent.ThreadID,
 88‚Üí			Subject:   dispatchSubject(item),
 89‚Üí			FromEmail: fromAddress,
 90‚Üí			ToEmails:  cmdutil.RecipientsJSON(item.ContactEmail),
 91‚Üí			Date:      attemptedAt.UTC().Format(time.RFC3339),
 92‚Üí			Labels:    `["SENT"]`,
 93‚Üí		}); err != nil {
 94‚Üí			return results, fmt.Errorf("email sent (message ID: %s) but failed to store local send state: %w", sent.MessageID, err)
 95‚Üí		}
 96‚Üí		if _, err := sequence.AdvanceTaskAfterSend(d, sequence.AdvanceOptions{
 97‚Üí			TaskID:    item.ID,
 98‚Üí			ThreadID:  sent.ThreadID,
 99‚Üí			MessageID: sent.MessageID,
100‚Üí			MailboxID: item.SelectedMailboxID,
101‚Üí			SentAt:    attemptedAt,
102‚Üí		}); err != nil {
103‚Üí			return results, fmt.Errorf("email sent (message ID: %s) but failed to advance task %s: %w", sent.MessageID, item.ID, err)
104‚Üí		}
105‚Üí		if err := sequence.LogSendAttempt(d, sequence.SendAttemptOptions{
106‚Üí			MailboxID:    item.SelectedMailboxID,
107‚Üí			EnrollmentID: item.EnrollmentID,
108‚Üí			TaskID:       item.ID,
109‚Üí			ContactEmail: item.ContactEmail,
110‚Üí			SendType:     item.SendType,
111‚Üí			Status:       "sent",
112‚Üí			Subject:      dispatchSubject(item),
113‚Üí			MessageID:    sent.MessageID,
114‚Üí			AttemptedAt:  attemptedAt,
115‚Üí		}); err != nil {
116‚Üí			return results, err
117‚Üí		}
118‚Üí
119‚Üí		results = append(results, dispatcherExecutionResult{
120‚Üí			TaskID:       item.ID,
121‚Üí			ContactEmail: item.ContactEmail,
122‚Üí			MailboxEmail: item.SelectedMailboxEmail,
123‚Üí			MessageID:    sent.MessageID,
124‚Üí			Status:       "sent",
125‚Üí		})
126‚Üí	}
127‚Üí	return results, nil
128‚Üí}
129‚Üí
130‚Üífunc dispatchSubject(item sequence.DispatchTask) string {
131‚Üí	if strings.TrimSpace(item.RenderedSubject) != "" {
132‚Üí		return strings.TrimSpace(item.RenderedSubject)
133‚Üí	}
134‚Üí	return strings.TrimSpace(item.Subject)
135‚Üí}
136‚Üí
137‚Üífunc shellSnippet(value string) string {
138‚Üí	if value == "" {
139‚Üí		return "''"
140‚Üí	}
141‚Üí	return "'" + strings.ReplaceAll(value, "'", `'"'"'`) + "'"
142‚Üí}
