 13‚Üífunc (g *GenericConnector) connectOAuth2(ctx context.Context) (*Result, error) {
 14‚Üí	var oauthCfg *oauth2.Config
 15‚Üí	var authOpts []oauth2.AuthCodeOption
 16‚Üí
 17‚Üí	if g.def.Credentials.Source == "google_json" {
 18‚Üí		// Google-specific: use google.ConfigFromJSON
 19‚Üí		credsData, err := g.loadGoogleCredentials()
 20‚Üí		if err != nil {
 21‚Üí			return nil, err
 22‚Üí		}
 23‚Üí		cfg, err := google.ConfigFromJSON(credsData, g.def.Auth.Scopes...)
 24‚Üí		if err != nil {
 25‚Üí			return nil, fmt.Errorf("parsing Google credentials: %w", err)
 26‚Üí		}
 27‚Üí		oauthCfg = cfg
 28‚Üí	} else {
 29‚Üí		// Generic OAuth2: build config from YAML
 30‚Üí		clientID, clientSecret, err := g.resolveOAuthCredentials()
 31‚Üí		if err != nil {
 32‚Üí			return nil, err
 33‚Üí		}
 34‚Üí		cfg, opts, err := g.buildOAuthConfig(clientID, clientSecret)
 35‚Üí		if err != nil {
 36‚Üí			return nil, err
 37‚Üí		}
 38‚Üí		oauthCfg = cfg
 39‚Üí		authOpts = opts
 40‚Üí	}
 41‚Üí
 42‚Üí	// Add extra_params as auth options for google_json too
 43‚Üí	if g.def.Credentials.Source == "google_json" {
 44‚Üí		for k, v := range g.def.Auth.ExtraParams {
 45‚Üí			authOpts = append(authOpts, oauth2.SetAuthURLParam(k, v))
 46‚Üí		}
 47‚Üí	}
 48‚Üí
 49‚Üí	// Run shared OAuth flow
 50‚Üí	token, err := OAuthFlow(ctx, oauthCfg, authOpts...)
 51‚Üí	if err != nil {
 52‚Üí		return nil, err
 53‚Üí	}
 54‚Üí
 55‚Üí	// Save token
 56‚Üí	tokenDir := fmt.Sprintf(".nurge/connectors/%s", g.def.ID)
 57‚Üí	tokenPath := tokenDir + "/token.json"
 58‚Üí	if err := os.MkdirAll(tokenDir, 0700); err != nil {
 59‚Üí		return nil, fmt.Errorf("creating connector dir: %w", err)
 60‚Üí	}
 61‚Üí	if err := saveToken(tokenPath, token); err != nil {
 62‚Üí		return nil, fmt.Errorf("saving token: %w", err)
 63‚Üí	}
 64‚Üí
 65‚Üí	// Verify connection + get account identifier
 66‚Üí	account, err := g.runVerify(ctx, oauthCfg, token)
 67‚Üí	if err != nil {
 68‚Üí		// Non-fatal: connected but can't verify
 69‚Üí		account = "connected (unverified)"
 70‚Üí	}
 71‚Üí
 72‚Üí	return &Result{
 73‚Üí		Account: account,
 74‚Üí		Token:   token,
 75‚Üí	}, nil
 76‚Üí}
