 78‚Üífunc (g *GenericConnector) connectAPIKey(ctx context.Context) (*Result, error) {
 79‚Üí	key := os.Getenv(g.def.Auth.EnvVar)
 80‚Üí	if key == "" {
 81‚Üí		// Check if stdin is a TTY for prompt
 82‚Üí		if fi, err := os.Stdin.Stat(); err == nil && fi.Mode()&os.ModeCharDevice != 0 {
 83‚Üí			fmt.Printf("Enter your %s API key: ", g.def.Name)
 84‚Üí			fmt.Scanln(&key)
 85‚Üí		}
 86‚Üí		if key == "" {
 87‚Üí			return nil, fmt.Errorf("%s API key not found. Set %s environment variable", g.def.Name, g.def.Auth.EnvVar)
 88‚Üí		}
 89‚Üí	}
 90‚Üí
 91‚Üí	// Save API key
 92‚Üí	tokenDir := fmt.Sprintf(".nurge/connectors/%s", g.def.ID)
 93‚Üí	if err := os.MkdirAll(tokenDir, 0700); err != nil {
 94‚Üí		return nil, fmt.Errorf("creating connector dir: %w", err)
 95‚Üí	}
 96‚Üí	credsPath := tokenDir + "/credentials.json"
 97‚Üí	credsData, _ := json.Marshal(map[string]string{"api_key": key})
 98‚Üí	if err := os.WriteFile(credsPath, credsData, 0600); err != nil {
 99‚Üí		return nil, fmt.Errorf("saving credentials: %w", err)
100‚Üí	}
101‚Üí
102‚Üí	// Verify
103‚Üí	account, err := g.runVerifyAPIKey(ctx, key)
104‚Üí	if err != nil {
105‚Üí		account = "connected (unverified)"
106‚Üí	}
107‚Üí
108‚Üí	return &Result{
109‚Üí		Account: account,
110‚Üí		Meta:    map[string]string{"api_key": key},
111‚Üí	}, nil
112‚Üí}
