159‚Üí// buildOAuthConfig creates a generic oauth2.Config from the YAML definition.
160‚Üífunc (g *GenericConnector) buildOAuthConfig(clientID, clientSecret string) (*oauth2.Config, []oauth2.AuthCodeOption, error) {
161‚Üí	cfg := &oauth2.Config{
162‚Üí		ClientID:     clientID,
163‚Üí		ClientSecret: clientSecret,
164‚Üí		Scopes:       g.def.Auth.Scopes,
165‚Üí		Endpoint: oauth2.Endpoint{
166‚Üí			AuthURL:  g.def.Auth.AuthorizeURL,
167‚Üí			TokenURL: g.def.Auth.TokenURL,
168‚Üí		},
169‚Üí	}
170‚Üí
171‚Üí	// Auth style
172‚Üí	switch g.def.Auth.AuthStyle {
173‚Üí	case "in_params":
174‚Üí		cfg.Endpoint.AuthStyle = oauth2.AuthStyleInParams
175‚Üí	case "in_header":
176‚Üí		cfg.Endpoint.AuthStyle = oauth2.AuthStyleInHeader
177‚Üí	}
178‚Üí
179‚Üí	// Extra params become AuthCodeOptions
180‚Üí	var opts []oauth2.AuthCodeOption
181‚Üí	for k, v := range g.def.Auth.ExtraParams {
182‚Üí		opts = append(opts, oauth2.SetAuthURLParam(k, v))
183‚Üí	}
184‚Üí
185‚Üí	return cfg, opts, nil
186‚Üí}
187‚Üí
188‚Üí// resolveOAuthCredentials reads client ID and secret from the configured source.
189‚Üífunc (g *GenericConnector) resolveOAuthCredentials() (string, string, error) {
190‚Üí	cred := g.def.Credentials
191‚Üí
192‚Üí	switch cred.Source {
193‚Üí	case "env":
194‚Üí		id := os.Getenv(cred.ClientIDVar)
195‚Üí		secret := os.Getenv(cred.ClientSecretVar)
196‚Üí		if id == "" || secret == "" {
197‚Üí			return "", "", fmt.Errorf("%s credentials not configured.\n  Set %s and %s environment variables",
198‚Üí				g.def.Name, cred.ClientIDVar, cred.ClientSecretVar)
199‚Üí		}
200‚Üí		return id, secret, nil
201‚Üí
202‚Üí	case "prompt":
203‚Üí		if fi, err := os.Stdin.Stat(); err != nil || fi.Mode()&os.ModeCharDevice == 0 {
204‚Üí			return "", "", fmt.Errorf("%s requires interactive input for credentials. Set environment variables or use a credentials file instead", g.def.Name)
205‚Üí		}
206‚Üí		var id, secret string
207‚Üí		fmt.Printf("Enter %s client ID: ", g.def.Name)
208‚Üí		fmt.Scanln(&id)
209‚Üí		fmt.Printf("Enter %s client secret: ", g.def.Name)
210‚Üí		fmt.Scanln(&secret)
211‚Üí		if id == "" || secret == "" {
212‚Üí			return "", "", fmt.Errorf("client ID and secret are required")
213‚Üí		}
214‚Üí		return id, secret, nil
215‚Üí
216‚Üí	default:
217‚Üí		return "", "", fmt.Errorf("unsupported credential source %q for connector %s", cred.Source, g.def.ID)
218‚Üí	}
219‚Üí}
