221‚Üí// loadGoogleCredentials loads credentials for google_json source (fallback chain).
222‚Üífunc (g *GenericConnector) loadGoogleCredentials() ([]byte, error) {
223‚Üí	// 1. Explicit path from --credentials flag
224‚Üí	if g.credentials != "" {
225‚Üí		data, err := os.ReadFile(g.credentials)
226‚Üí		if err != nil {
227‚Üí			return nil, fmt.Errorf("reading credentials from %s: %w", g.credentials, err)
228‚Üí		}
229‚Üí		return data, nil
230‚Üí	}
231‚Üí
232‚Üí	// 2. Local file in project
233‚Üí	localPath := fmt.Sprintf(".nurge/connectors/%s/credentials.json", g.def.ID)
234‚Üí	if data, err := os.ReadFile(localPath); err == nil {
235‚Üí		return data, nil
236‚Üí	}
237‚Üí
238‚Üí	// 3. Bundled credentials
239‚Üí	if len(BundledCredentials) > 0 {
240‚Üí		return BundledCredentials, nil
241‚Üí	}
242‚Üí
243‚Üí	return nil, fmt.Errorf("no %s credentials found -- provide a credentials.json file", g.def.Name)
244‚Üí}
