  5‚Üí// Shared Unipile send helper ‚Äî used by both cron dispatcher and sync httpAction
  6‚Üíexport async function callUnipileSend(args: {
  7‚Üí  accountId: string;
  8‚Üí  to: string;
  9‚Üí  subject: string;
 10‚Üí  body: string;
 11‚Üí  replyTo?: string;
 12‚Üí}): Promise<
 13‚Üí  | { ok: true; messageId: string; providerId: string }
 14‚Üí  | { ok: false; error: string; authError: boolean }
 15‚Üí> {
 16‚Üí  const apiKey = process.env.UNIPILE_API_KEY;
 17‚Üí  const apiUrl = process.env.UNIPILE_API_URL;
 18‚Üí  if (!apiKey || !apiUrl) {
 19‚Üí    return { ok: false, error: "Unipile API key or URL not configured", authError: false };
 20‚Üí  }
 21‚Üí
 22‚Üí  const payload: Record<string, any> = {
 23‚Üí    account_id: args.accountId,
 24‚Üí    to: [{ identifier: args.to }],
 25‚Üí    subject: args.subject,
 26‚Üí    body: args.body,
 27‚Üí  };
 28‚Üí
 29‚Üí  if (args.replyTo) {
 30‚Üí    payload.reply_to = args.replyTo;
 31‚Üí  }
 32‚Üí
 33‚Üí  const resp = await fetch(`${apiUrl}/api/v1/emails`, {
 34‚Üí    method: "POST",
 35‚Üí    headers: {
 36‚Üí      "X-API-KEY": apiKey,
 37‚Üí      "Content-Type": "application/json",
 38‚Üí    },
 39‚Üí    body: JSON.stringify(payload),
 40‚Üí  });
 41‚Üí
 42‚Üí  if (!resp.ok) {
 43‚Üí    const errorText = await resp.text();
 44‚Üí    const isAuth = resp.status === 401 || resp.status === 403;
 45‚Üí    return {
 46‚Üí      ok: false,
 47‚Üí      error: isAuth ? `Auth error: ${errorText}` : `Unipile API error ${resp.status}: ${errorText}`,
 48‚Üí      authError: isAuth,
 49‚Üí    };
 50‚Üí  }
 51‚Üí
 52‚Üí  const result = await resp.json();
 53‚Üí  return {
 54‚Üí    ok: true,
 55‚Üí    messageId: result.id || "",
 56‚Üí    providerId: JSON.stringify(result.provider_id || ""),
 57‚Üí  };
 58‚Üí}
 59‚Üí
 60‚Üí// Send via Unipile ‚Äî called by cron dispatcher
 61‚Üíexport const sendViaUnipile = internalAction({
 62‚Üí  args: {
 63‚Üí    userId: v.string(),
 64‚Üí    taskId: v.string(), // externalId of follow_up_task
 65‚Üí    accountId: v.string(), // Unipile account ID
 66‚Üí    to: v.string(),
 67‚Üí    subject: v.string(),
 68‚Üí    body: v.string(),
 69‚Üí    replyTo: v.optional(v.string()), // provider_id for threading
 70‚Üí  },
 71‚Üí  handler: async (ctx, args) => {
 72‚Üí    const result = await callUnipileSend({
 73‚Üí      accountId: args.accountId,
 74‚Üí      to: args.to,
 75‚Üí      subject: args.subject,
 76‚Üí      body: args.body,
 77‚Üí      replyTo: args.replyTo,
 78‚Üí    });
 79‚Üí
 80‚Üí    if (!result.ok) {
 81‚Üí      if (result.authError) {
 82‚Üí        await ctx.runMutation(internal.send.recordAuthFailure, {
 83‚Üí          userId: args.userId,
 84‚Üí          taskId: args.taskId,
 85‚Üí          mailboxId: "",
 86‚Üí          error: result.error,
 87‚Üí        });
 88‚Üí      } else {
 89‚Üí        await ctx.runMutation(internal.send.recordSendFailure, {
 90‚Üí          userId: args.userId,
 91‚Üí          taskId: args.taskId,
 92‚Üí          error: result.error,
 93‚Üí        });
 94‚Üí      }
 95‚Üí      return { ok: false, error: result.error };
 96‚Üí    }
 97‚Üí
 98‚Üí    await ctx.runMutation(internal.send.recordSendSuccess, {
 99‚Üí      userId: args.userId,
100‚Üí      taskId: args.taskId,
101‚Üí      unipileMessageId: result.messageId,
102‚Üí      providerId: result.providerId,
103‚Üí    });
104‚Üí
105‚Üí    return { ok: true, messageId: result.messageId, providerId: result.providerId };
106‚Üí  },
107‚Üí});
