109‚Üí// Record successful send ‚Äî updates task, creates send event, advances enrollment
110‚Üíexport const recordSendSuccess = internalMutation({
111‚Üí  args: {
112‚Üí    userId: v.string(),
113‚Üí    taskId: v.string(),
114‚Üí    unipileMessageId: v.string(),
115‚Üí    providerId: v.string(),
116‚Üí  },
117‚Üí  handler: async (ctx, args) => {
118‚Üí    const task = await ctx.db
119‚Üí      .query("followUpTasks")
120‚Üí      .withIndex("by_external_id", (q) => q.eq("externalId", args.taskId))
121‚Üí      .first();
122‚Üí
123‚Üí    if (!task) return;
124‚Üí
125‚Üí    const syncState = await ctx.db
126‚Üí      .query("syncState")
127‚Üí      .withIndex("by_user", (q) => q.eq("userId", args.userId))
128‚Üí      .first();
129‚Üí    let version = (syncState?.lastSyncVersion ?? 0) + 1;
130‚Üí
131‚Üí    // Update task
132‚Üí    await ctx.db.patch(task._id, {
133‚Üí      status: "completed",
134‚Üí      sendStatus: "sent",
135‚Üí      completedAt: new Date().toISOString(),
136‚Üí      unipileMessageId: args.unipileMessageId,
137‚Üí      providerId: args.providerId,
138‚Üí      syncVersion: version,
139‚Üí    });
140‚Üí
141‚Üí    // Create send event
142‚Üí    const sendEventId = `mse-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
143‚Üí    await ctx.db.insert("mailboxSendEvents", {
144‚Üí      externalId: sendEventId,
145‚Üí      mailboxId: task.mailboxId,
146‚Üí      sendType: task.sendType,
147‚Üí      sentAt: new Date().toISOString(),
148‚Üí      taskId: args.taskId,
149‚Üí      enrollmentId: task.enrollmentId,
150‚Üí      unipileMessageId: args.unipileMessageId,
151‚Üí      providerId: args.providerId,
152‚Üí      syncVersion: version,
153‚Üí      userId: args.userId,
154‚Üí    });
155‚Üí
156‚Üí    // Advance enrollment
157‚Üí    const enrollment = await ctx.db
158‚Üí      .query("sequenceEnrollments")
159‚Üí      .withIndex("by_external_id", (q) => q.eq("externalId", task.enrollmentId))
160‚Üí      .first();
161‚Üí
162‚Üí    if (enrollment) {
163‚Üí      version++;
164‚Üí      const newStep = task.stepNumber;
165‚Üí      const isComplete = newStep >= enrollment.totalSteps;
166‚Üí
167‚Üí      await ctx.db.patch(enrollment._id, {
168‚Üí        currentStep: newStep,
169‚Üí        lastSentAt: new Date().toISOString(),
170‚Üí        lastMessageId: args.unipileMessageId,
171‚Üí        status: isComplete ? "completed" : enrollment.status,
172‚Üí        nextDueAt: isComplete ? "" : enrollment.nextDueAt,
173‚Üí        unipileThreadProviderId: args.providerId || enrollment.unipileThreadProviderId,
174‚Üí        syncVersion: version,
175‚Üí      });
176‚Üí
177‚Üí      // Mark draft as sent
178‚Üí      const draft = await ctx.db
179‚Üí        .query("sequenceDrafts")
180‚Üí        .withIndex("by_task", (q) => q.eq("taskId", args.taskId))
181‚Üí        .first();
182‚Üí      if (draft) {
183‚Üí        await ctx.db.patch(draft._id, {
184‚Üí          status: "sent",
185‚Üí          syncVersion: version,
186‚Üí        });
187‚Üí      }
188‚Üí    }
189‚Üí
190‚Üí    // Update sync state
191‚Üí    if (syncState) {
192‚Üí      await ctx.db.patch(syncState._id, { lastSyncVersion: version });
193‚Üí    } else {
194‚Üí      await ctx.db.insert("syncState", { userId: args.userId, lastSyncVersion: version });
195‚Üí    }
196‚Üí  },
197‚Üí});
198‚Üí
199‚Üí// Record send failure ‚Äî increment attempt count, set error
200‚Üíexport const recordSendFailure = internalMutation({
201‚Üí  args: {
202‚Üí    userId: v.string(),
203‚Üí    taskId: v.string(),
204‚Üí    error: v.string(),
205‚Üí  },
206‚Üí  handler: async (ctx, args) => {
207‚Üí    const task = await ctx.db
208‚Üí      .query("followUpTasks")
209‚Üí      .withIndex("by_external_id", (q) => q.eq("externalId", args.taskId))
210‚Üí      .first();
211‚Üí
212‚Üí    if (!task) return;
213‚Üí
214‚Üí    const syncState = await ctx.db
215‚Üí      .query("syncState")
216‚Üí      .withIndex("by_user", (q) => q.eq("userId", args.userId))
217‚Üí      .first();
218‚Üí    const version = (syncState?.lastSyncVersion ?? 0) + 1;
219‚Üí
220‚Üí    const newAttemptCount = task.attemptCount + 1;
221‚Üí    const maxRetries = 5;
222‚Üí
223‚Üí    // Check stale window (48 hours past due)
224‚Üí    const dueAt = new Date(task.dueAt).getTime();
225‚Üí    const now = Date.now();
226‚Üí    const staleWindowMs = 48 * 60 * 60 * 1000;
227‚Üí    const isStale = now - dueAt > staleWindowMs;
228‚Üí
229‚Üí    const isFailed = newAttemptCount >= maxRetries || isStale;
230‚Üí
231‚Üí    await ctx.db.patch(task._id, {
232‚Üí      sendStatus: isFailed ? "failed" : "pending", // back to pending for retry
233‚Üí      lastAttemptAt: new Date().toISOString(),
234‚Üí      lastError: args.error,
235‚Üí      attemptCount: newAttemptCount,
236‚Üí      status: isFailed ? "canceled" : task.status,
237‚Üí      canceledReason: isFailed
238‚Üí        ? isStale
239‚Üí          ? "stale: past 48h window"
240‚Üí          : `max retries (${maxRetries}) exceeded`
241‚Üí        : task.canceledReason,
242‚Üí      syncVersion: version,
243‚Üí    });
244‚Üí
245‚Üí    if (syncState) {
246‚Üí      await ctx.db.patch(syncState._id, { lastSyncVersion: version });
247‚Üí    } else {
248‚Üí      await ctx.db.insert("syncState", { userId: args.userId, lastSyncVersion: version });
249‚Üí    }
250‚Üí  },
251‚Üí});
252‚Üí
253‚Üí// Record auth failure ‚Äî mark mailbox as auth_expired, pause enrollment
254‚Üíexport const recordAuthFailure = internalMutation({
255‚Üí  args: {
256‚Üí    userId: v.string(),
257‚Üí    taskId: v.string(),
258‚Üí    mailboxId: v.string(),
259‚Üí    error: v.string(),
260‚Üí  },
261‚Üí  handler: async (ctx, args) => {
262‚Üí    const task = await ctx.db
263‚Üí      .query("followUpTasks")
264‚Üí      .withIndex("by_external_id", (q) => q.eq("externalId", args.taskId))
265‚Üí      .first();
266‚Üí
267‚Üí    if (!task) return;
268‚Üí
269‚Üí    const syncState = await ctx.db
270‚Üí      .query("syncState")
271‚Üí      .withIndex("by_user", (q) => q.eq("userId", args.userId))
272‚Üí      .first();
273‚Üí    let version = (syncState?.lastSyncVersion ?? 0) + 1;
274‚Üí
275‚Üí    // Mark task as failed (don't retry auth errors)
276‚Üí    await ctx.db.patch(task._id, {
277‚Üí      sendStatus: "failed",
278‚Üí      lastError: args.error,
279‚Üí      lastAttemptAt: new Date().toISOString(),
280‚Üí      syncVersion: version,
281‚Üí    });
282‚Üí
283‚Üí    // Mark mailbox as auth_expired
284‚Üí    const mailbox = await ctx.db
285‚Üí      .query("mailboxes")
286‚Üí      .withIndex("by_external_id", (q) => q.eq("externalId", task.mailboxId))
287‚Üí      .first();
288‚Üí
289‚Üí    if (mailbox) {
290‚Üí      version++;
291‚Üí      await ctx.db.patch(mailbox._id, {
292‚Üí        status: "auth_expired",
293‚Üí        syncVersion: version,
294‚Üí      });
295‚Üí    }
296‚Üí
297‚Üí    if (syncState) {
298‚Üí      await ctx.db.patch(syncState._id, { lastSyncVersion: version });
299‚Üí    } else {
300‚Üí      await ctx.db.insert("syncState", { userId: args.userId, lastSyncVersion: version });
301‚Üí    }
302‚Üí  },
303‚Üí});
