 12‚Üí// POST /api/send-email ‚Äî single endpoint for all CLI-initiated sends
 13‚Üí//
 14‚Üí// Sync sends (sync: true): calls Unipile immediately, returns result.
 15‚Üí// Async sends (sync: false): creates task with pending status, cron picks it up.
 16‚Üí// Sequence sends: creates enrollment + future follow-up tasks + drafts.
 17‚Üíexport const sendEmail = httpAction(async (ctx, request) => {
 18‚Üí  try {
 19‚Üí    const payload = await request.json();
 20‚Üí
 21‚Üí    // --- Auth ---
 22‚Üí    const authHeader = request.headers.get("Authorization");
 23‚Üí    if (!authHeader || !authHeader.startsWith("Bearer ")) {
 24‚Üí      return jsonResponse({ ok: false, error: "Missing auth token" }, 401);
 25‚Üí    }
 26‚Üí    const token = authHeader.slice(7);
 27‚Üí
 28‚Üí    const user = await ctx.runQuery(internal.sendApi.findUserByToken, { token });
 29‚Üí    if (!user) {
 30‚Üí      return jsonResponse({ ok: false, error: "Invalid auth token" }, 401);
 31‚Üí    }
 32‚Üí    const userId = user._id;
 33‚Üí
 34‚Üí    // --- Validate required fields ---
 35‚Üí    const { to, subject, body, sendType, sync, taskId, sequence } = payload;
 36‚Üí
 37‚Üí    // If taskId is provided, we're sending an existing task
 38‚Üí    if (taskId) {
 39‚Üí      return await handleExistingTask(ctx, userId, taskId, payload);
 40‚Üí    }
 41‚Üí
 42‚Üí    if (!to || !subject || !body) {
 43‚Üí      return jsonResponse({ ok: false, error: "to, subject, and body are required" }, 400);
 44‚Üí    }
 45‚Üí
 46‚Üí    // --- Look up Unipile account ---
 47‚Üí    const unipileAccount = await ctx.runQuery(internal.sendApi.findUnipileAccount, {
 48‚Üí      userId,
 49‚Üí      provider: "GOOGLE",
 50‚Üí    });
 51‚Üí    if (!unipileAccount) {
 52‚Üí      return jsonResponse({ ok: false, error: "No connected email account. Run: nurge connect gmail" }, 400);
 53‚Üí    }
 54‚Üí    if (unipileAccount.status !== "connected") {
 55‚Üí      const msg = unipileAccount.status === "disconnected"
 56‚Üí        ? "Email account disconnected. Reconnect via nurge connect gmail"
 57‚Üí        : "Email account auth expired. Re-authenticate via nurge connect gmail";
 58‚Üí      return jsonResponse({ ok: false, error: msg }, 400);
 59‚Üí    }
 60‚Üí
 61‚Üí    // --- Resolve mailbox ---
 62‚Üí    const mailboxId = sequence?.mailboxId || null;
 63‚Üí    const mailbox = mailboxId
 64‚Üí      ? await ctx.runQuery(internal.sendApi.findMailboxById, { externalId: mailboxId })
 65‚Üí      : await ctx.runQuery(internal.sendApi.findActiveMailbox, { userId });
 66‚Üí
 67‚Üí    if (!mailbox) {
 68‚Üí      return jsonResponse({ ok: false, error: "No active mailbox found" }, 400);
 69‚Üí    }
 70‚Üí    if (mailbox.status === "auth_expired") {
 71‚Üí      return jsonResponse({ ok: false, error: "Mailbox auth expired. Re-authenticate via nurge connect gmail" }, 400);
 72‚Üí    }
 73‚Üí
 74‚Üí    // --- Suppression check ---
 75‚Üí    const suppression = await ctx.runQuery(internal.sendApi.checkSuppression, { userId, email: to });
 76‚Üí    if (suppression.suppressed) {
 77‚Üí      return jsonResponse({ ok: false, error: `Contact suppressed: ${suppression.reason}` }, 400);
 78‚Üí    }
 79‚Üí
 80‚Üí    // --- Send window + daily cap ---
 81‚Üí    const effectiveSendType = sendType || "first_touch";
 82‚Üí    if (!withinSendWindow(mailbox.sendWindowStartHour, mailbox.sendWindowEndHour, mailbox.sendWindowTimezone)) {
 83‚Üí      if (sync) {
 84‚Üí        return jsonResponse({ ok: false, error: "Outside send window" }, 400);
 85‚Üí      }
 86‚Üí      // Async: task will be picked up when window opens
 87‚Üí    }
 88‚Üí
 89‚Üí    const today = todayInTimezone(mailbox.sendWindowTimezone);
 90‚Üí    const sendCount = await ctx.runQuery(internal.sendApi.countSends, {
 91‚Üí      mailboxId: mailbox.externalId,
 92‚Üí      sendType: effectiveSendType,
 93‚Üí      day: today,
 94‚Üí    });
 95‚Üí    const capMap: Record<string, number> = {
 96‚Üí      first_touch: mailbox.firstTouchDailyCap,
 97‚Üí      follow_up: mailbox.followUpDailyCap,
 98‚Üí      reply: mailbox.replyDailyCap,
 99‚Üí    };
100‚Üí    const cap = capMap[effectiveSendType] || 0;
101‚Üí    if (cap > 0 && sendCount >= cap) {
102‚Üí      if (sync) {
103‚Üí        return jsonResponse({ ok: false, error: `Daily ${effectiveSendType} cap reached (${cap})` }, 400);
104‚Üí      }
105‚Üí    }
106‚Üí
107‚Üí    // --- Generate IDs ---
108‚Üí    const now = new Date().toISOString();
109‚Üí    const taskExternalId = `task-${Date.now()}-${randomSuffix()}`;
110‚Üí    const enrollmentExternalId = sequence ? `enr-${Date.now()}-${randomSuffix()}` : "";
111‚Üí
112‚Üí    // --- Create enrollment + future tasks if sequence ---
113‚Üí    if (sequence) {
114‚Üí      // Check for existing active enrollment
115‚Üí      const existingEnrollment = await ctx.runQuery(internal.sendApi.findActiveEnrollment, {
116‚Üí        userId,
117‚Üí        mailboxId: mailbox.externalId,
118‚Üí        contactEmail: to,
119‚Üí      });
120‚Üí      if (existingEnrollment) {
121‚Üí        return jsonResponse({
122‚Üí          ok: false,
123‚Üí          error: `${to} already has an active sequence enrollment (${existingEnrollment.externalId})`,
124‚Üí        }, 400);
125‚Üí      }
126‚Üí
127‚Üí      await ctx.runMutation(internal.sendApi.createSendEnrollment, {
128‚Üí        userId,
129‚Üí        enrollment: {
130‚Üí          externalId: enrollmentExternalId,
131‚Üí          sequenceName: sequence.sequenceName,
132‚Üí          campaignName: sequence.campaignName || "",
133‚Üí          mailboxId: mailbox.externalId,
134‚Üí          contactEmail: to,
135‚Üí          contactName: sequence.contactName || "",
136‚Üí          subject,
137‚Üí          currentStep: 1,
138‚Üí          totalSteps: 1 + (sequence.steps?.length || 0),
139‚Üí          initialBody: body,
140‚Üí          unipileAccountId: unipileAccount.unipileAccountId,
141‚Üí        },
142‚Üí        firstTask: {
143‚Üí          externalId: taskExternalId,
144‚Üí          stepNumber: 1,
145‚Üí          stepName: "first_touch",
146‚Üí          sendType: "first_touch",
147‚Üí          dueAt: now,
148‚Üí          subject,
149‚Üí          body,
150‚Üí          contactEmail: to,
151‚Üí          mailboxId: mailbox.externalId,
152‚Üí        },
153‚Üí        futureSteps: (sequence.steps || []).map((step: any, i: number) => {
154‚Üí          const stepTaskId = `task-${Date.now()}-${randomSuffix()}-s${step.stepNumber || i + 2}`;
155‚Üí          const draftId = `draft-${Date.now()}-${randomSuffix()}-s${step.stepNumber || i + 2}`;
156‚Üí          const dueDate = new Date(Date.now() + (step.delayDays || 3) * 86400000).toISOString();
157‚Üí          return {
158‚Üí            task: {
159‚Üí              externalId: stepTaskId,
160‚Üí              stepNumber: step.stepNumber || i + 2,
161‚Üí              stepName: step.stepName || `follow_up_${i + 1}`,
162‚Üí              sendType: step.sendType || "follow_up",
163‚Üí              dueAt: dueDate,
164‚Üí              subject: step.subject || subject,
165‚Üí              body: step.body || "",
166‚Üí              contactEmail: to,
167‚Üí              mailboxId: mailbox.externalId,
168‚Üí            },
169‚Üí            draft: {
170‚Üí              externalId: draftId,
171‚Üí              taskId: stepTaskId,
172‚Üí              stepNumber: step.stepNumber || i + 2,
173‚Üí              subject: step.subject || subject,
174‚Üí              body: step.body || "",
175‚Üí              channel: "email",
176‚Üí            },
177‚Üí          };
178‚Üí        }),
179‚Üí      });
180‚Üí    } else {
181‚Üí      // One-off send: create standalone task
182‚Üí      await ctx.runMutation(internal.sendApi.createStandaloneTask, {
183‚Üí        userId,
184‚Üí        task: {
185‚Üí          externalId: taskExternalId,
186‚Üí          enrollmentId: "",
187‚Üí          mailboxId: mailbox.externalId,
188‚Üí          contactEmail: to,
189‚Üí          subject,
190‚Üí          body,
191‚Üí          stepNumber: 1,
192‚Üí          sendType: effectiveSendType,
193‚Üí          dueAt: now,
194‚Üí        },
195‚Üí      });
196‚Üí    }
197‚Üí
198‚Üí    // --- Sync: send now ---
199‚Üí    if (sync) {
200‚Üí      const sendResult = await callUnipileSend({
201‚Üí        accountId: unipileAccount.unipileAccountId,
202‚Üí        to,
203‚Üí        subject,
204‚Üí        body,
205‚Üí      });
206‚Üí
207‚Üí      if (!sendResult.ok) {
208‚Üí        await ctx.runMutation(internal.sendApi.markTaskFailed, {
209‚Üí          userId,
210‚Üí          taskId: taskExternalId,
211‚Üí          error: sendResult.error,
212‚Üí          authError: sendResult.authError,
213‚Üí          mailboxId: mailbox.externalId,
214‚Üí        });
215‚Üí        return jsonResponse({ ok: false, error: sendResult.error }, 502);
216‚Üí      }
217‚Üí
218‚Üí      await ctx.runMutation(internal.sendApi.markTaskSent, {
219‚Üí        userId,
220‚Üí        taskId: taskExternalId,
221‚Üí        enrollmentId: enrollmentExternalId,
222‚Üí        mailboxId: mailbox.externalId,
223‚Üí        sendType: effectiveSendType,
224‚Üí        unipileMessageId: sendResult.messageId,
225‚Üí        providerId: sendResult.providerId,
226‚Üí      });
227‚Üí
228‚Üí      return jsonResponse({
229‚Üí        ok: true,
230‚Üí        messageId: sendResult.messageId,
231‚Üí        providerId: sendResult.providerId,
232‚Üí        taskId: taskExternalId,
233‚Üí        enrollmentId: enrollmentExternalId || undefined,
234‚Üí      });
235‚Üí    }
236‚Üí
237‚Üí    // --- Async: return queued ---
238‚Üí    return jsonResponse({
239‚Üí      ok: true,
240‚Üí      queued: true,
241‚Üí      taskId: taskExternalId,
242‚Üí      enrollmentId: enrollmentExternalId || undefined,
243‚Üí    });
244‚Üí  } catch (error: any) {
245‚Üí    console.error("sendEmail error:", error);
246‚Üí    return jsonResponse({ ok: false, error: error.message || "Internal error" }, 500);
247‚Üí  }
248‚Üí});
