250‚Üí// Handle sending an existing task (--task-id flow)
251‚Üíasync function handleExistingTask(ctx: any, userId: string, taskId: string, payload: any) {
252‚Üí  const task = await ctx.runQuery(internal.sendApi.findTask, { externalId: taskId });
253‚Üí  if (!task) {
254‚Üí    return jsonResponse({ ok: false, error: `Task ${taskId} not found` }, 404);
255‚Üí  }
256‚Üí  if (task.userId !== userId) {
257‚Üí    return jsonResponse({ ok: false, error: "Task does not belong to this user" }, 403);
258‚Üí  }
259‚Üí  if (task.status !== "open") {
260‚Üí    return jsonResponse({ ok: false, error: `Task is ${task.status}, not open` }, 400);
261‚Üí  }
262‚Üí  if (task.sendStatus === "sent") {
263‚Üí    return jsonResponse({ ok: false, error: "Task already sent" }, 400);
264‚Üí  }
265‚Üí
266‚Üí  // Resolve Unipile account
267‚Üí  const unipileAccount = await ctx.runQuery(internal.sendApi.findUnipileAccount, {
268‚Üí    userId,
269‚Üí    provider: "GOOGLE",
270‚Üí  });
271‚Üí  if (!unipileAccount) {
272‚Üí    return jsonResponse({ ok: false, error: "No connected email account" }, 400);
273‚Üí  }
274‚Üí  if (unipileAccount.status !== "connected") {
275‚Üí    const msg = unipileAccount.status === "disconnected"
276‚Üí      ? "Email account disconnected. Reconnect via nurge connect gmail"
277‚Üí      : "Email account auth expired. Re-authenticate via nurge connect gmail";
278‚Üí    return jsonResponse({ ok: false, error: msg }, 400);
279‚Üí  }
280‚Üí
281‚Üí  // Use payload overrides or task defaults
282‚Üí  const to = payload.to || task.contactEmail;
283‚Üí  const subject = payload.subject || task.subject || "";
284‚Üí  const body = payload.body || task.body || "";
285‚Üí
286‚Üí  // Look up draft for latest content
287‚Üí  const draft = await ctx.runQuery(internal.sendApi.findDraft, { taskId });
288‚Üí  const finalSubject = subject || draft?.subject || "";
289‚Üí  const finalBody = body || draft?.body || "";
290‚Üí
291‚Üí  if (!finalSubject || !finalBody) {
292‚Üí    return jsonResponse({ ok: false, error: "No subject or body available for this task" }, 400);
293‚Üí  }
294‚Üí
295‚Üí  // Get enrollment for threading
296‚Üí  const enrollment = task.enrollmentId
297‚Üí    ? await ctx.runQuery(internal.sendApi.findEnrollment, { externalId: task.enrollmentId })
298‚Üí    : null;
299‚Üí
300‚Üí  const replyTo = enrollment?.unipileThreadProviderId || undefined;
301‚Üí
302‚Üí  const sendResult = await callUnipileSend({
303‚Üí    accountId: unipileAccount.unipileAccountId,
304‚Üí    to,
305‚Üí    subject: finalSubject,
306‚Üí    body: finalBody,
307‚Üí    replyTo,
308‚Üí  });
309‚Üí
310‚Üí  if (!sendResult.ok) {
311‚Üí    await ctx.runMutation(internal.sendApi.markTaskFailed, {
312‚Üí      userId,
313‚Üí      taskId,
314‚Üí      error: sendResult.error,
315‚Üí      authError: sendResult.authError,
316‚Üí      mailboxId: task.mailboxId,
317‚Üí    });
318‚Üí    return jsonResponse({ ok: false, error: sendResult.error }, 502);
319‚Üí  }
320‚Üí
321‚Üí  await ctx.runMutation(internal.sendApi.markTaskSent, {
322‚Üí    userId,
323‚Üí    taskId,
324‚Üí    enrollmentId: task.enrollmentId,
325‚Üí    mailboxId: task.mailboxId,
326‚Üí    sendType: task.sendType,
327‚Üí    unipileMessageId: sendResult.messageId,
328‚Üí    providerId: sendResult.providerId,
329‚Üí  });
330‚Üí
331‚Üí  return jsonResponse({
332‚Üí    ok: true,
333‚Üí    messageId: sendResult.messageId,
334‚Üí    providerId: sendResult.providerId,
335‚Üí    taskId,
336‚Üí    enrollmentId: task.enrollmentId || undefined,
337‚Üí  });
338‚Üí}
