457‚Üíexport const createStandaloneTask = internalMutation({
458‚Üí  args: {
459‚Üí    userId: v.string(),
460‚Üí    task: v.object({
461‚Üí      externalId: v.string(),
462‚Üí      enrollmentId: v.string(),
463‚Üí      mailboxId: v.string(),
464‚Üí      contactEmail: v.string(),
465‚Üí      subject: v.string(),
466‚Üí      body: v.string(),
467‚Üí      stepNumber: v.float64(),
468‚Üí      sendType: v.string(),
469‚Üí      dueAt: v.string(),
470‚Üí    }),
