708‚Üí          syncVersion: version,
709‚Üí        });
710‚Üí
711‚Üí        // Mark draft as sent
712‚Üí        const draft = await ctx.db
713‚Üí          .query("sequenceDrafts")
714‚Üí          .withIndex("by_task", (q) => q.eq("taskId", args.taskId))
