 1‚Üíimport { cronJobs } from "convex/server";
 2‚Üíimport { internal } from "./_generated/api";
 3‚Üí
 4‚Üíconst crons = cronJobs();
 5‚Üí
 6‚Üí// Check for due tasks every 5 minutes
 7‚Üícrons.interval(
 8‚Üí  "check due sequence tasks",
 9‚Üí  { minutes: 5 },
10‚Üí  internal.dispatcher.checkDueTasks,
11‚Üí);
