  1‚Üíimport { v } from "convex/values";
  2‚Üíimport { internalAction, internalQuery, internalMutation } from "./_generated/server";
  3‚Üíimport { internal } from "./_generated/api";
  4‚Üíimport {
  5‚Üí  isSuppressed,
  6‚Üí  countSendsForDay,
  7‚Üí  todayInTimezone,
  8‚Üí  withinSendWindow,
  9‚Üí} from "./helpers";
 10‚Üí
 11‚Üíconst BATCH_SIZE = 10;
 12‚Üí
 13‚Üí// Cron entry point: find due tasks, validate, dispatch sends
 14‚Üíexport const checkDueTasks = internalAction({
 15‚Üí  handler: async (ctx) => {
 16‚Üí    const now = new Date().toISOString();
 17‚Üí
 18‚Üí    const dueTasks = await ctx.runQuery(internal.dispatcher.findDueTasks, {
 19‚Üí      now,
 20‚Üí      limit: BATCH_SIZE,
 21‚Üí    });
 22‚Üí
 23‚Üí    if (dueTasks.length === 0) return;
 24‚Üí
 25‚Üí    for (const task of dueTasks) {
 26‚Üí      try {
 27‚Üí        const enrollment = await ctx.runQuery(
 28‚Üí          internal.dispatcher.getEnrollment,
 29‚Üí          { enrollmentId: task.enrollmentId }
 30‚Üí        );
 31‚Üí        if (!enrollment || enrollment.status !== "active") continue;
 32‚Üí
 33‚Üí        const suppression = await ctx.runQuery(
 34‚Üí          internal.dispatcher.checkSuppression,
 35‚Üí          { userId: task.userId, email: task.contactEmail }
 36‚Üí        );
 37‚Üí        if (suppression.suppressed) {
 38‚Üí          await ctx.runMutation(internal.dispatcher.cancelTask, {
 39‚Üí            taskId: task.externalId,
 40‚Üí            userId: task.userId,
 41‚Üí            reason: `Contact suppressed: ${suppression.reason}`,
 42‚Üí          });
 43‚Üí          continue;
 44‚Üí        }
 45‚Üí
 46‚Üí        const mailbox = await ctx.runQuery(
 47‚Üí          internal.dispatcher.getMailbox,
 48‚Üí          { mailboxId: task.mailboxId }
 49‚Üí        );
 50‚Üí        if (!mailbox || mailbox.status !== "active") continue;
 51‚Üí        if (
 52‚Üí          !withinSendWindow(
 53‚Üí            mailbox.sendWindowStartHour,
 54‚Üí            mailbox.sendWindowEndHour,
 55‚Üí            mailbox.sendWindowTimezone
 56‚Üí          )
 57‚Üí        ) {
 58‚Üí          continue;
 59‚Üí        }
 60‚Üí
 61‚Üí        const today = todayInTimezone(mailbox.sendWindowTimezone);
 62‚Üí        const sendCount = await ctx.runQuery(
 63‚Üí          internal.dispatcher.countSends,
 64‚Üí          { mailboxId: task.mailboxId, sendType: task.sendType, day: today }
 65‚Üí        );
 66‚Üí
 67‚Üí        const capMap: Record<string, number> = {
 68‚Üí          first_touch: mailbox.firstTouchDailyCap,
 69‚Üí          follow_up: mailbox.followUpDailyCap,
 70‚Üí          reply: mailbox.replyDailyCap,
 71‚Üí        };
 72‚Üí        const cap = capMap[task.sendType] || 0;
 73‚Üí        if (cap > 0 && sendCount >= cap) continue;
 74‚Üí
 75‚Üí        const draft = await ctx.runQuery(
 76‚Üí          internal.dispatcher.getDraft,
 77‚Üí          { taskId: task.externalId }
 78‚Üí        );
 79‚Üí        if (draft && draft.status === "stale") continue;
 80‚Üí
 81‚Üí        await ctx.runMutation(internal.dispatcher.claimTask, {
 82‚Üí          taskId: task.externalId,
 83‚Üí          userId: task.userId,
 84‚Üí        });
 85‚Üí
 86‚Üí        const unipileAccount = await ctx.runQuery(
 87‚Üí          internal.dispatcher.getUnipileAccount,
 88‚Üí          { userId: task.userId, provider: "GOOGLE" }
 89‚Üí        );
 90‚Üí        if (!unipileAccount) continue;
 91‚Üí
 92‚Üí        const subject = draft?.subject || task.subject || "";
 93‚Üí        const body = draft?.body || task.body || "";
 94‚Üí
 95‚Üí        await ctx.runAction(internal.send.sendViaUnipile, {
 96‚Üí          userId: task.userId,
 97‚Üí          taskId: task.externalId,
 98‚Üí          accountId: unipileAccount.unipileAccountId,
 99‚Üí          to: task.contactEmail,
100‚Üí          subject,
101‚Üí          body,
102‚Üí          replyTo: enrollment.unipileThreadProviderId || undefined,
103‚Üí        });
104‚Üí      } catch (error) {
105‚Üí        console.error(`Error processing task ${task.externalId}:`, error);
106‚Üí      }
107‚Üí    }
108‚Üí  },
109‚Üí});
