113‚Üíexport const findDueTasks = internalQuery({
114‚Üí  args: { now: v.string(), limit: v.float64() },
115‚Üí  handler: async (ctx, args) => {
116‚Üí    const tasks = await ctx.db
117‚Üí      .query("followUpTasks")
118‚Üí      .filter((q) =>
119‚Üí        q.and(
120‚Üí          q.eq(q.field("sendStatus"), "pending"),
121‚Üí          q.eq(q.field("status"), "open"),
122‚Üí          q.lte(q.field("dueAt"), args.now)
123‚Üí        )
124‚Üí      )
125‚Üí      .take(args.limit);
126‚Üí
127‚Üí    return tasks.map((t) => ({
128‚Üí      externalId: t.externalId,
129‚Üí      enrollmentId: t.enrollmentId,
130‚Üí      mailboxId: t.mailboxId,
131‚Üí      contactEmail: t.contactEmail,
132‚Üí      sendType: t.sendType,
133‚Üí      subject: t.subject,
134‚Üí      body: t.body,
135‚Üí      userId: t.userId,
136‚Üí    }));
137‚Üí  },
138‚Üí});
