package seq

import (
	"database/sql"
	"fmt"
	"strings"
	"time"

	"github.com/usenurge/nurgesh/cmd/cmdutil"
	"github.com/usenurge/nurgesh/internal/email"
	"github.com/usenurge/nurgesh/internal/sequence"
	gm "google.golang.org/api/gmail/v1"
)

func executeDispatch(srv *gm.Service, d *sql.DB, dispatch []sequence.DispatchTask) ([]dispatcherExecutionResult, error) {
	results := make([]dispatcherExecutionResult, 0, len(dispatch))
	for _, item := range dispatch {
		if !item.Ready {
			continue
		}

		attemptedAt := time.Now()
		fromAddress := strings.TrimSpace(item.TransportEmail)
		if fromAddress == "" {
			fromAddress = strings.TrimSpace(item.SelectedMailboxEmail)
		}
		if fromAddress == "" {
			results = append(results, dispatcherExecutionResult{
				TaskID:       item.ID,
				ContactEmail: item.ContactEmail,
				MailboxEmail: item.SelectedMailboxEmail,
				Status:       "failed",
				Error:        "no transport address available for task",
			})
			continue
		}

		sent, err := email.Send(srv, fromAddress, email.SendOptions{
			To:       item.ContactEmail,
			Subject:  dispatchSubject(item),
			Body:     item.RenderedBody,
			ThreadID: item.ThreadID,
		})
		if err != nil {
			if markErr := sequence.MarkTaskAttempt(d, item.ID, attemptedAt, err); markErr != nil {
				return results, markErr
			}
			if updateErr := sequence.UpdateTaskSendState(d, item.ID, sequence.TaskSendStatusFailed, "", "", err.Error()); updateErr != nil {
				return results, updateErr
			}
			if logErr := sequence.LogSendAttempt(d, sequence.SendAttemptOptions{
				MailboxID:    item.SelectedMailboxID,
				EnrollmentID: item.EnrollmentID,
				TaskID:       item.ID,
				ContactEmail: item.ContactEmail,
				SendType:     item.SendType,
				Status:       "failed",
				Subject:      dispatchSubject(item),
				Error:        err.Error(),
				AttemptedAt:  attemptedAt,
			}); logErr != nil {
				return results, logErr
			}
			results = append(results, dispatcherExecutionResult{
				TaskID:       item.ID,
				ContactEmail: item.ContactEmail,
				MailboxEmail: item.SelectedMailboxEmail,
				Status:       "failed",
				Error:        err.Error(),
			})
			continue
		}

		if err := sequence.MarkTaskAttempt(d, item.ID, attemptedAt, nil); err != nil {
			return results, err
		}
		if err := sequence.UpdateTaskSendState(d, item.ID, sequence.TaskSendStatusSent, sent.MessageID, "", ""); err != nil {
			return results, err
		}
		if err := sequence.RecordSend(d, item.SelectedMailboxID, item.SendType, attemptedAt); err != nil {
			return results, fmt.Errorf("email sent (message ID: %s) but failed to record mailbox usage: %w", sent.MessageID, err)
		}
		if err := email.StoreEmail(d, &email.RawMessage{
			ID:        sent.MessageID,
			Source:    "gmail",
			Direction: "outbound",
			ThreadID:  sent.ThreadID,
			Subject:   dispatchSubject(item),
			FromEmail: fromAddress,
			ToEmails:  cmdutil.RecipientsJSON(item.ContactEmail),
			Date:      attemptedAt.UTC().Format(time.RFC3339),
			Labels:    `["SENT"]`,
		}); err != nil {
			return results, fmt.Errorf("email sent (message ID: %s) but failed to store local send state: %w", sent.MessageID, err)
		}
		if _, err := sequence.AdvanceTaskAfterSend(d, sequence.AdvanceOptions{
			TaskID:    item.ID,
			ThreadID:  sent.ThreadID,
			MessageID: sent.MessageID,
			MailboxID: item.SelectedMailboxID,
			SentAt:    attemptedAt,
		}); err != nil {
			return results, fmt.Errorf("email sent (message ID: %s) but failed to advance task %s: %w", sent.MessageID, item.ID, err)
		}
		if err := sequence.LogSendAttempt(d, sequence.SendAttemptOptions{
			MailboxID:    item.SelectedMailboxID,
			EnrollmentID: item.EnrollmentID,
			TaskID:       item.ID,
			ContactEmail: item.ContactEmail,
			SendType:     item.SendType,
			Status:       "sent",
			Subject:      dispatchSubject(item),
			MessageID:    sent.MessageID,
			AttemptedAt:  attemptedAt,
		}); err != nil {
			return results, err
		}

		results = append(results, dispatcherExecutionResult{
			TaskID:       item.ID,
			ContactEmail: item.ContactEmail,
			MailboxEmail: item.SelectedMailboxEmail,
			MessageID:    sent.MessageID,
			Status:       "sent",
		})
	}
	return results, nil
}

func dispatchSubject(item sequence.DispatchTask) string {
	if strings.TrimSpace(item.RenderedSubject) != "" {
		return strings.TrimSpace(item.RenderedSubject)
	}
	return strings.TrimSpace(item.Subject)
}

func shellSnippet(value string) string {
	if value == "" {
		return "''"
	}
	return "'" + strings.ReplaceAll(value, "'", `'"'"'`) + "'"
}

package email

import (
	"context"
	"encoding/json"
	"fmt"
	"os"

	"golang.org/x/oauth2"
	"golang.org/x/oauth2/google"
	gm "google.golang.org/api/gmail/v1"
	"google.golang.org/api/option"

	"github.com/usenurge/nurgesh/internal/connector"
)

const defaultTokenPath = ".nurge/connectors/gmail/token.json"

// NewClient creates an authenticated Gmail service from a saved token.
func NewClient(tokenPath string) (*gm.Service, error) {
	if tokenPath == "" {
		tokenPath = defaultTokenPath
	}

	tokenData, err := os.ReadFile(tokenPath)
	if err != nil {
		return nil, fmt.Errorf("reading token: %w", err)
	}

	var token oauth2.Token
	if err := json.Unmarshal(tokenData, &token); err != nil {
		return nil, fmt.Errorf("parsing token: %w", err)
	}

	credsData, err := connector.LoadCredentials("gmail")
	if err != nil {
		return nil, err
	}

	oauthCfg, err := google.ConfigFromJSON(credsData,
		gm.GmailReadonlyScope,
		gm.GmailSendScope,
		gm.GmailModifyScope,
	)
	if err != nil {
		return nil, fmt.Errorf("parsing credentials: %w", err)
	}

	client := oauthCfg.Client(context.Background(), &token)
	srv, err := gm.NewService(context.Background(), option.WithHTTPClient(client))
	if err != nil {
		return nil, fmt.Errorf("creating Gmail service: %w", err)
	}

	return srv, nil
}

package account

import (
	"bytes"
	"encoding/json"
	"fmt"
	"io"
	"net/http"
	"time"
)

// SendEmailRequest is the payload for the /api/send-email endpoint.
type SendEmailRequest struct {
	To       string           `json:"to"`
	Cc       string           `json:"cc,omitempty"`
	Subject  string           `json:"subject"`
	Body     string           `json:"body"`
	SendType string           `json:"sendType"`
	Sync     bool             `json:"sync"`
	TaskID   string           `json:"taskId,omitempty"`
	Sequence *SequenceRequest `json:"sequence,omitempty"`
}

// SequenceRequest defines sequence enrollment details for a send.
type SequenceRequest struct {
	SequenceName string         `json:"sequenceName"`
	CampaignName string         `json:"campaignName,omitempty"`
	ContactName  string         `json:"contactName,omitempty"`
	MailboxID    string         `json:"mailboxId,omitempty"`
	Steps        []SequenceStep `json:"steps,omitempty"`
}

// SequenceStep defines a future step in a sequence.
type SequenceStep struct {
	StepNumber int    `json:"stepNumber"`
	StepName   string `json:"stepName,omitempty"`
	SendType   string `json:"sendType"`
	DelayDays  int    `json:"delayDays"`
	Subject    string `json:"subject,omitempty"`
	Body       string `json:"body,omitempty"`
}

// SendEmailResponse is the response from the /api/send-email endpoint.
type SendEmailResponse struct {
	OK           bool   `json:"ok"`
	Queued       bool   `json:"queued,omitempty"`
	MessageID    string `json:"messageId,omitempty"`
	ProviderID   string `json:"providerId,omitempty"`
	EnrollmentID string `json:"enrollmentId,omitempty"`
	TaskID       string `json:"taskId,omitempty"`
	Error        string `json:"error,omitempty"`
}

// SendEmail calls the Convex /api/send-email endpoint.
func (c *ConvexClient) SendEmail(token string, req SendEmailRequest) (*SendEmailResponse, error) {
	body, err := json.Marshal(req)
	if err != nil {
		return nil, fmt.Errorf("marshaling request: %w", err)
	}

	httpReq, err := http.NewRequest("POST", c.baseURL+"/api/send-email", bytes.NewReader(body))
	if err != nil {
		return nil, fmt.Errorf("creating request: %w", err)
	}
	httpReq.Header.Set("Content-Type", "application/json")
	httpReq.Header.Set("Authorization", "Bearer "+token)

	resp, err := c.httpClient.Do(httpReq)
	if err != nil {
		return nil, fmt.Errorf("calling send-email: %w", err)
	}
	defer resp.Body.Close()

	data, err := io.ReadAll(resp.Body)
	if err != nil {
		return nil, fmt.Errorf("reading response: %w", err)
	}

	var result SendEmailResponse
	if err := json.Unmarshal(data, &result); err != nil {
		return nil, fmt.Errorf("parsing response: %w", err)
	}

	if !result.OK {
		return &result, fmt.Errorf("%s", result.Error)
	}
	return &result, nil
}

// ConnectGmailResponse is returned by /api/connect-gmail.
type ConnectGmailResponse struct {
	URL              string `json:"url,omitempty"`
	AlreadyConnected bool   `json:"already_connected,omitempty"`
	MaxReached       bool   `json:"max_reached,omitempty"`
	Email            string `json:"email,omitempty"`
	Error            string `json:"error,omitempty"`
}

