package email

import (
	"fmt"
	"strings"

	"github.com/spf13/cobra"
	"github.com/usenurge/nurgesh/cmd/cmdutil"
	"github.com/usenurge/nurgesh/internal/account"
	"github.com/usenurge/nurgesh/internal/db"
	"github.com/usenurge/nurgesh/internal/sequence"
)

var (
	sendTo          string
	sendCc          string
	sendSubject     string
	sendBody        string
	sendSequence    string
	sendCampaign    string
	sendTaskID      string
	sendSendType    string
	sendContactName string
)

var sendCmd = &cobra.Command{
	Use:   "send",
	Short: "Send an email via Unipile",
	Long:  "Send an email through your connected email account via Convex + Unipile.",
	RunE: func(cmd *cobra.Command, args []string) error {
		if sendSequence != "" && sendTaskID != "" {
			return fmt.Errorf("--sequence and --task-id cannot be used together")
		}

		// Load auth token
		authFile, err := account.LoadAuth()
		if err != nil || authFile.Token == "" {
			return fmt.Errorf("not logged in. Run: nurge account login")
		}

		// If --task-id is provided, resolve draft content from local DB for defaults
		if sendTaskID != "" {
			d, err := db.Open()
			if err != nil {
				return fmt.Errorf("opening database: %w", err)
			}
			defer d.Close()

			task, err := sequence.TaskByID(d, sendTaskID)
			if err != nil {
				return err
			}
			if sendTo == "" {
				sendTo = task.ContactEmail
			} else if !strings.EqualFold(strings.TrimSpace(sendTo), strings.TrimSpace(task.ContactEmail)) {
				return fmt.Errorf("--task-id %s belongs to %s, but --to was %s", task.ID, task.ContactEmail, sendTo)
			}
			if sendSubject == "" || sendBody == "" {
				renderedSubject, renderedBody, err := sequence.RenderTaskContent(d, *task)
				if err != nil {
					return err
				}
				if sendSubject == "" {
					sendSubject = renderedSubject
				}
				if sendBody == "" {
					sendBody = renderedBody
				}
			}
		}

		if sendTo == "" {
			return fmt.Errorf("recipient (--to) is required")
		}
		if sendSubject == "" {
			return fmt.Errorf("subject (--subject) is required")
		}
		if sendBody == "" {
			return fmt.Errorf("body (--body) is required")
		}

		// Build request
		req := account.SendEmailRequest{
			To:       strings.TrimSpace(sendTo),
			Cc:       strings.TrimSpace(sendCc),
			Subject:  sendSubject,
			Body:     sendBody,
			SendType: sequence.NormalizeSendType(sendSendType),
			Sync:     true, // CLI-initiated sends are always sync
			TaskID:   sendTaskID,
		}

		// Sequence enrollment
		if sendSequence != "" {
			req.SendType = sequence.SendTypeFirstTouch

			d, err := db.Open()
			if err != nil {
				return fmt.Errorf("opening database: %w", err)
			}
			defer d.Close()

			seqReq := &account.SequenceRequest{
				SequenceName: sendSequence,
				CampaignName: sendCampaign,
				ContactName:  sendContactName,
			}

			// Best-effort mailbox resolution for Convex
			if sendCampaign != "" {
				if campaign, cErr := sequence.CampaignByName(d, sendCampaign); cErr == nil {
					if mbx, mErr := sequence.CampaignMailbox(d, campaign); mErr == nil && mbx != nil {
						seqReq.MailboxID = mbx.ID
					}
				}
			}

			// Get steps from built-in template
			tmpl, tmplErr := sequence.TemplateByName(d, sendSequence)
			if tmplErr == nil {
				for _, step := range tmpl.Steps {
					if step.StepNumber <= 1 {
						continue // skip first touch, that's the current send
					}
					seqReq.Steps = append(seqReq.Steps, account.SequenceStep{
						StepNumber: step.StepNumber,
						StepName:   step.Name,
						SendType:   step.SendType,
						DelayDays:  parseDays(step.Delay),
					})
				}
			}

			req.Sequence = seqReq
		}

		// Call Convex
		client := account.NewConvexClient(cmdutil.GetConvexURL())
		resp, err := client.SendEmail(authFile.Token, req)
		if err != nil {
			return fmt.Errorf("send failed: %w", err)
		}

		if resp.Queued {
			fmt.Printf("  \033[33m‚è≥\033[0m Queued for %s (task: %s)\n", sendTo, resp.TaskID)
		} else {
			fmt.Printf("  \033[32m‚úì\033[0m Sent to %s (message ID: %s)\n", sendTo, resp.MessageID)
		}

		if resp.EnrollmentID != "" {
			fmt.Printf("  ‚Ü≥ Enrolled in sequence %s (%s)\n", sendSequence, resp.EnrollmentID)
		}

		return nil
	},
}

func init() {
	sendCmd.Flags().StringVar(&sendTo, "to", "", "Recipient email address")
	sendCmd.Flags().StringVar(&sendCc, "cc", "", "CC email address")
	sendCmd.Flags().StringVar(&sendSubject, "subject", "", "Email subject")
	sendCmd.Flags().StringVar(&sendBody, "body", "", "Email body (plain text)")
	sendCmd.Flags().StringVar(&sendSequence, "sequence", "", "Enroll the sent email in a built-in sequence template")
	sendCmd.Flags().StringVar(&sendCampaign, "campaign", "", "Optional campaign name stored on the sequence enrollment")
	sendCmd.Flags().StringVar(&sendTaskID, "task-id", "", "Mark a follow-up task as sent and advance the sequence")
	sendCmd.Flags().StringVar(&sendSendType, "send-type", "", "Override send classification (first_touch, follow_up, reply, manual)")
	sendCmd.Flags().StringVar(&sendContactName, "contact-name", "", "Optional prospect name stored on sequence enrollment")
}

// parseDays extracts day count from a duration string like "3d" or "72h".
func parseDays(delay string) int {
	delay = strings.TrimSpace(delay)
	if delay == "" || delay == "0s" {
		return 0
	}
	// Handle "Xd" format
	if strings.HasSuffix(delay, "d") {
		var d int
		fmt.Sscanf(delay, "%dd", &d)
		return d
	}
	// Handle "Xh" format
	if strings.HasSuffix(delay, "h") {
		var h int
		fmt.Sscanf(delay, "%dh", &h)
		return h / 24
	}
	return 3 // default
}

