import { httpRouter } from "convex/server";
import { unipileWebhook, unipileAccountCallback } from "./webhook";
import { sendEmail } from "./sendApi";
import { googleAuth, validateToken, revokeToken } from "./auth";
import { connectGmail, connectLinkedin, connectionStatus, connectSuccess, connectLinkedinSuccess, syncEmails } from "./connect";
import { enrichCompany, enrichPerson, enrichSearch } from "./enrich";

const http = httpRouter();

// ‚îÄ‚îÄ Auth ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ

http.route({
  path: "/api/google-auth",
  method: "POST",
  handler: googleAuth,
});

http.route({
  path: "/api/validate-token",
  method: "POST",
  handler: validateToken,
});

http.route({
  path: "/api/revoke-token",
  method: "POST",
  handler: revokeToken,
});

// ‚îÄ‚îÄ Unipile ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ

http.route({
  path: "/api/unipile-webhook",
  method: "POST",
  handler: unipileWebhook,
});

http.route({
  path: "/api/unipile-account-callback",
  method: "POST",
  handler: unipileAccountCallback,
});

// ‚îÄ‚îÄ CLI API ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ

http.route({
  path: "/api/send-email",
  method: "POST",
  handler: sendEmail,
});

// ‚îÄ‚îÄ Connect ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ

http.route({
  path: "/api/connect-gmail",
  method: "POST",
  handler: connectGmail,
});

http.route({
  path: "/api/connect-linkedin",
  method: "POST",
  handler: connectLinkedin,
});

http.route({
  path: "/api/connection-status",
  method: "GET",
  handler: connectionStatus,
});

http.route({
  path: "/api/connect-success",
  method: "GET",
  handler: connectSuccess,
});

http.route({
  path: "/api/connect-linkedin-success",
  method: "GET",
  handler: connectLinkedinSuccess,
});

http.route({
  path: "/api/sync-emails",
  method: "POST",
  handler: syncEmails,
});

// ‚îÄ‚îÄ Enrich ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ

http.route({
  path: "/api/enrich-company",
  method: "POST",
  handler: enrichCompany,
});

http.route({
  path: "/api/enrich-person",
  method: "POST",
  handler: enrichPerson,
});

http.route({
  path: "/api/enrich-search",
  method: "POST",
  handler: enrichSearch,
});

export default http;

