  1‚Üíimport { v } from "convex/values";
  2‚Üíimport { httpAction, internalQuery, internalMutation } from "./_generated/server";
  3‚Üíimport { api, internal } from "./_generated/api";
  4‚Üí
  5‚Üí// Unipile webhook receiver ‚Äî handles new emails, tracking, account status
  6‚Üíexport const unipileWebhook = httpAction(async (ctx, request) => {
  7‚Üí  // Verify Unipile-Auth shared secret
  8‚Üí  const secret = process.env.UNIPILE_WEBHOOK_SECRET;
  9‚Üí  const authHeader = request.headers.get("Unipile-Auth");
 10‚Üí
 11‚Üí  if (secret && authHeader !== secret) {
 12‚Üí    console.error("Webhook auth failed: invalid Unipile-Auth header");
 13‚Üí    return new Response("Unauthorized", { status: 401 });
 14‚Üí  }
 15‚Üí
 16‚Üí  try {
 17‚Üí    const payload = await request.json();
 18‚Üí    const eventType = payload.event || payload.type;
 19‚Üí
 20‚Üí    switch (eventType) {
 21‚Üí      case "new_email":
 22‚Üí      case "mail.received":
 23‚Üí        await handleNewEmail(ctx, payload);
 24‚Üí        break;
 25‚Üí
 26‚Üí      case "email_tracking":
 27‚Üí      case "mail.tracking":
 28‚Üí        // Log open/click events ‚Äî useful for analytics
 29‚Üí        console.log("Email tracking event:", JSON.stringify(payload));
 30‚Üí        break;
 31‚Üí
 32‚Üí      case "account.status":
 33‚Üí      case "account_status":
 34‚Üí        await handleAccountStatus(ctx, payload);
 35‚Üí        break;
 36‚Üí
 37‚Üí      default:
 38‚Üí        console.log("Unknown webhook event:", eventType, JSON.stringify(payload));
 39‚Üí    }
 40‚Üí
 41‚Üí    return new Response("OK", { status: 200 });
 42‚Üí  } catch (error: any) {
 43‚Üí    console.error("Webhook processing error:", error);
 44‚Üí    return new Response("Internal error", { status: 500 });
 45‚Üí  }
 46‚Üí});
 47‚Üí
 48‚Üíasync function handleNewEmail(ctx: any, payload: any) {
 49‚Üí  const email = payload.data || payload;
 50‚Üí  const providerId = email.provider_id
 51‚Üí    ? JSON.stringify(email.provider_id)
 52‚Üí    : "";
 53‚Üí  const accountId = email.account_id || "";
 54‚Üí  const from = email.from?.identifier || email.from_email || "";
 55‚Üí  const threadId = email.thread_id || "";
 56‚Üí
 57‚Üí  // Find the Unipile account to get the userId
 58‚Üí  const account = accountId
 59‚Üí    ? await ctx.runQuery(internal.webhook.findAccountByUnipileId, {
 60‚Üí        unipileAccountId: accountId,
 61‚Üí      })
 62‚Üí    : null;
 63‚Üí
 64‚Üí  if (!account) {
 65‚Üí    console.log("No matching Unipile account for:", accountId);
 66‚Üí    return;
 67‚Üí  }
 68‚Üí
 69‚Üí  // Check if this email is on a thread with an active enrollment
 70‚Üí  if (threadId || providerId) {
 71‚Üí    await ctx.runMutation(internal.webhook.processReply, {
 72‚Üí      userId: account.userId,
 73‚Üí      fromEmail: from,
 74‚Üí      threadId,
 75‚Üí      providerId,
 76‚Üí      messageId: email.id || "",
 77‚Üí      subject: email.subject || "",
 78‚Üí      snippet: email.body_plain?.substring(0, 200) || "",
 79‚Üí    });
 80‚Üí  }
 81‚Üí}
 82‚Üí
 83‚Üíasync function handleAccountStatus(ctx: any, payload: any) {
 84‚Üí  const data = payload.data || payload;
 85‚Üí  const accountId = data.account_id || "";
 86‚Üí  const status = data.status || "";
 87‚Üí
 88‚Üí  if (status === "disconnected" || status === "error") {
 89‚Üí    const account = await ctx.runQuery(
 90‚Üí      internal.webhook.findAccountByUnipileId,
 91‚Üí      { unipileAccountId: accountId }
 92‚Üí    );
 93‚Üí
 94‚Üí    if (account) {
 95‚Üí      // Use the actual status from Unipile: "disconnected" vs "auth_expired"
 96‚Üí      const convexStatus = status === "disconnected" ? "disconnected" : "auth_expired";
 97‚Üí      await ctx.runMutation(internal.webhook.updateAccountStatus, {
 98‚Üí        userId: account.userId,
 99‚Üí        unipileAccountId: accountId,
100‚Üí        status: convexStatus,
101‚Üí      });
102‚Üí    }
103‚Üí  }
104‚Üí}
105‚Üí
106‚Üí// Unipile account callback ‚Äî called when user completes hosted auth
107‚Üíexport const unipileAccountCallback = httpAction(async (ctx, request) => {
108‚Üí  try {
109‚Üí    const payload = await request.json();
110‚Üí    console.log("Unipile callback received:", JSON.stringify(payload));
111‚Üí    const accountId = payload.account_id || "";
112‚Üí    const rawName = payload.name || ""; // Encoded as "userId:PROVIDER" by requestConnectionLink
113‚Üí    const email = payload.identifier || "";
114‚Üí
115‚Üí    // Parse userId and provider from the encoded name field
116‚Üí    let userId = rawName;
117‚Üí    let provider = "GOOGLE"; // Fallback for older links without encoded provider
118‚Üí    if (rawName.includes(":")) {
119‚Üí      const sepIndex = rawName.lastIndexOf(":");
120‚Üí      userId = rawName.substring(0, sepIndex);
121‚Üí      provider = rawName.substring(sepIndex + 1) || "GOOGLE";
122‚Üí    }
123‚Üí
124‚Üí    if (!accountId || !userId) {
125‚Üí      return new Response("Missing account_id or name", { status: 400 });
126‚Üí    }
127‚Üí
128‚Üí    await ctx.runMutation(internal.webhook.registerUnipileAccount, {
129‚Üí      userId,
130‚Üí      unipileAccountId: accountId,
131‚Üí      provider,
132‚Üí      email,
133‚Üí    });
134‚Üí
135‚Üí    // Schedule backfill asynchronously (only for email providers)
136‚Üí    if (provider === "GOOGLE") {
137‚Üí      await ctx.scheduler.runAfter(0, api.unipile.backfillEmails, {
138‚Üí        userId,
139‚Üí        unipileAccountId: accountId,
140‚Üí      });
141‚Üí    }
142‚Üí
143‚Üí    return new Response("OK", { status: 200 });
144‚Üí  } catch (error: any) {
145‚Üí    console.error("Account callback error:", error);
146‚Üí    return new Response("Internal error", { status: 500 });
147‚Üí  }
148‚Üí});
149‚Üí
150‚Üí// --- Internal functions used by webhook handlers ---
151‚Üí
152‚Üíexport const findAccountByUnipileId = internalQuery({
153‚Üí  args: { unipileAccountId: v.string() },
154‚Üí  handler: async (ctx, args) => {
155‚Üí    return await ctx.db
156‚Üí      .query("unipileAccounts")
157‚Üí      .withIndex("by_unipile_id", (q) =>
158‚Üí        q.eq("unipileAccountId", args.unipileAccountId)
159‚Üí      )
160‚Üí      .first();
161‚Üí  },
162‚Üí});
163‚Üí
164‚Üíexport const processReply = internalMutation({
165‚Üí  args: {
166‚Üí    userId: v.string(),
167‚Üí    fromEmail: v.string(),
168‚Üí    threadId: v.string(),
169‚Üí    providerId: v.string(),
170‚Üí    messageId: v.string(),
171‚Üí    subject: v.optional(v.string()),
172‚Üí    snippet: v.optional(v.string()),
173‚Üí  },
174‚Üí  handler: async (ctx, args) => {
175‚Üí    // Find active enrollments for this contact
176‚Üí    const enrollments = await ctx.db
177‚Üí      .query("sequenceEnrollments")
178‚Üí      .withIndex("by_contact", (q) =>
