package email

import (
	"fmt"
	"time"

	gm "google.golang.org/api/gmail/v1"
)

// PubSubTopic is the Google Cloud Pub/Sub topic for Gmail push notifications.
// This must match the topic created in the Nurge GCP project.
const PubSubTopic = "projects/nurge-prod/topics/gmail-push"

// WatchResult holds the response from registering a Gmail watch.
type WatchResult struct {
	HistoryID  uint64
	Expiration time.Time
}

// Watch registers a Gmail Pub/Sub watch for real-time notifications.
// The watch sends notifications to the configured Pub/Sub topic when
// messages are added to SENT or INBOX labels.
//
// Watches expire after 7 days and must be renewed before expiry.
// Calling Watch again before expiry is safe (idempotent reset).
func Watch(srv *gm.Service) (*WatchResult, error) {
	resp, err := srv.Users.Watch("me", &gm.WatchRequest{
		TopicName: PubSubTopic,
		LabelIds:  []string{"SENT", "INBOX"},
	}).Do()
	if err != nil {
		return nil, fmt.Errorf("registering Gmail watch: %w", err)
	}

	expiration := time.UnixMilli(resp.Expiration)
	return &WatchResult{
		HistoryID:  resp.HistoryId,
		Expiration: expiration,
	}, nil
}

// StopWatch stops receiving push notifications for the authenticated user.
func StopWatch(srv *gm.Service) error {
	return srv.Users.Stop("me").Do()
}

