func RenewWatchIfNeeded(srv *gm.Service, watchExpiryPath string) (*WatchResult, error) {
	data, err := os.ReadFile(watchExpiryPath)
	if err != nil {
		// No watch state file -- register a fresh watch
		return renewAndSave(srv, watchExpiryPath)
	}

	expiry, err := time.Parse(time.RFC3339, strings.TrimSpace(string(data)))
	if err != nil {
		// Corrupt file -- re-register
		return renewAndSave(srv, watchExpiryPath)
	}

	// Renew if expiry is within 24 hours
	if time.Until(expiry) < 24*time.Hour {
		return renewAndSave(srv, watchExpiryPath)
	}

	return nil, nil // no renewal needed
}

