	result, err := Watch(srv)
	if err != nil {
		return nil, err
	}
	// Save expiry for next check
	_ = os.WriteFile(watchExpiryPath, []byte(result.Expiration.Format(time.RFC3339)), 0600)
	return result, nil
}

