import { v } from "convex/values";
import { internalAction, internalQuery, internalMutation } from "./_generated/server";
import { internal } from "./_generated/api";
import {
  isSuppressed,
  countSendsForDay,
  todayInTimezone,
  withinSendWindow,
} from "./helpers";

const BATCH_SIZE = 10;

// Cron entry point: find due tasks, validate, dispatch sends
export const checkDueTasks = internalAction({
  handler: async (ctx) => {
    const now = new Date().toISOString();

    const dueTasks = await ctx.runQuery(internal.dispatcher.findDueTasks, {
      now,
      limit: BATCH_SIZE,
    });

    if (dueTasks.length === 0) return;

    for (const task of dueTasks) {
      try {
        const enrollment = await ctx.runQuery(
          internal.dispatcher.getEnrollment,
          { enrollmentId: task.enrollmentId }
        );
        if (!enrollment || enrollment.status !== "active") continue;

        const suppression = await ctx.runQuery(
          internal.dispatcher.checkSuppression,
          { userId: task.userId, email: task.contactEmail }
        );
        if (suppression.suppressed) {
          await ctx.runMutation(internal.dispatcher.cancelTask, {
            taskId: task.externalId,
            userId: task.userId,
            reason: `Contact suppressed: ${suppression.reason}`,
          });
          continue;
        }

        const mailbox = await ctx.runQuery(
          internal.dispatcher.getMailbox,
          { mailboxId: task.mailboxId }
        );
        if (!mailbox || mailbox.status !== "active") continue;
        if (
          !withinSendWindow(
            mailbox.sendWindowStartHour,
            mailbox.sendWindowEndHour,
            mailbox.sendWindowTimezone
          )
        ) {
          continue;
        }

        const today = todayInTimezone(mailbox.sendWindowTimezone);
        const sendCount = await ctx.runQuery(
          internal.dispatcher.countSends,
          { mailboxId: task.mailboxId, sendType: task.sendType, day: today }
        );

        const capMap: Record<string, number> = {
          first_touch: mailbox.firstTouchDailyCap,
          follow_up: mailbox.followUpDailyCap,
          reply: mailbox.replyDailyCap,
        };
        const cap = capMap[task.sendType] || 0;
        if (cap > 0 && sendCount >= cap) continue;

        const draft = await ctx.runQuery(
          internal.dispatcher.getDraft,
          { taskId: task.externalId }
        );
        if (draft && draft.status === "stale") continue;

        await ctx.runMutation(internal.dispatcher.claimTask, {
          taskId: task.externalId,
          userId: task.userId,
        });

        const unipileAccount = await ctx.runQuery(
          internal.dispatcher.getUnipileAccount,
          { userId: task.userId, provider: "GOOGLE" }
        );
        if (!unipileAccount) continue;

        const subject = draft?.subject || task.subject || "";
        const body = draft?.body || task.body || "";

        await ctx.runAction(internal.send.sendViaUnipile, {
          userId: task.userId,
          taskId: task.externalId,
          accountId: unipileAccount.unipileAccountId,
          to: task.contactEmail,
          subject,
          body,
          replyTo: enrollment.unipileThreadProviderId || undefined,
        });
      } catch (error) {
        console.error(`Error processing task ${task.externalId}:`, error);
      }
    }
  },
});

// --- Internal queries/mutations used by checkDueTasks ---

export const findDueTasks = internalQuery({
  args: { now: v.string(), limit: v.float64() },
  handler: async (ctx, args) => {
    const tasks = await ctx.db
      .query("followUpTasks")
      .filter((q) =>
        q.and(
          q.eq(q.field("sendStatus"), "pending"),
          q.eq(q.field("status"), "open"),
          q.lte(q.field("dueAt"), args.now)
        )
      )
      .take(args.limit);

    return tasks.map((t) => ({
      externalId: t.externalId,
      enrollmentId: t.enrollmentId,
      mailboxId: t.mailboxId,
      contactEmail: t.contactEmail,
      sendType: t.sendType,
      subject: t.subject,
      body: t.body,
      userId: t.userId,
    }));
  },
});

export const getEnrollment = internalQuery({
  args: { enrollmentId: v.string() },
  handler: async (ctx, args) => {
    return await ctx.db
      .query("sequenceEnrollments")
      .withIndex("by_external_id", (q) => q.eq("externalId", args.enrollmentId))
      .first();
  },
});

export const checkSuppression = internalQuery({
  args: { userId: v.string(), email: v.string() },
  handler: async (ctx, args) => {
    return await isSuppressed(ctx, args.userId, args.email);
  },
});

export const getMailbox = internalQuery({
  args: { mailboxId: v.string() },
  handler: async (ctx, args) => {
    return await ctx.db
      .query("mailboxes")
      .withIndex("by_external_id", (q) => q.eq("externalId", args.mailboxId))
      .first();
  },
});

export const countSends = internalQuery({
  args: { mailboxId: v.string(), sendType: v.string(), day: v.string() },
  handler: async (ctx, args) => {
    return await countSendsForDay(ctx, args.mailboxId, args.sendType, args.day);
  },
});

export const getDraft = internalQuery({
  args: { taskId: v.string() },
  handler: async (ctx, args) => {
    return await ctx.db
      .query("sequenceDrafts")
      .withIndex("by_task", (q) => q.eq("taskId", args.taskId))
      .first();
  },
});

export const getUnipileAccount = internalQuery({
  args: { userId: v.string(), provider: v.string() },
  handler: async (ctx, args) => {
    const accounts = await ctx.db
      .query("unipileAccounts")
      .withIndex("by_provider", (q) =>
        q.eq("userId", args.userId).eq("provider", args.provider)
      )
      .collect();
    // Prefer connected accounts; skip disconnected/expired
    return accounts.find((a) => a.status === "connected") || null;
  },
});

export const claimTask = internalMutation({
  args: { taskId: v.string(), userId: v.string() },
  handler: async (ctx, args) => {
    const task = await ctx.db
      .query("followUpTasks")
      .withIndex("by_external_id", (q) => q.eq("externalId", args.taskId))
      .first();
    if (!task) return;

    await ctx.db.patch(task._id, {
      sendStatus: "pending_remote_send",
      lastAttemptAt: new Date().toISOString(),
    });
  },
});

export const cancelTask = internalMutation({
  args: { taskId: v.string(), userId: v.string(), reason: v.string() },
  handler: async (ctx, args) => {
    const task = await ctx.db
      .query("followUpTasks")
      .withIndex("by_external_id", (q) => q.eq("externalId", args.taskId))
      .first();
    if (!task) return;

    const syncState = await ctx.db
      .query("syncState")
      .withIndex("by_user", (q) => q.eq("userId", args.userId))
      .first();
    const version = (syncState?.lastSyncVersion ?? 0) + 1;

    await ctx.db.patch(task._id, {
      status: "canceled",
      sendStatus: "canceled",
      canceledReason: args.reason,
      syncVersion: version,
    });

    if (syncState) {
      await ctx.db.patch(syncState._id, { lastSyncVersion: version });
    } else {
      await ctx.db.insert("syncState", {
        userId: args.userId,
        lastSyncVersion: version,
      });
    }
  },
});

